// Unit 2: Entschuldigung, wo ist...?
// Level: A1

const UNIT_2 =
{n:2,lang:"de",srcLang:"en",track:"v2",title:"Entschuldigung, wo ist...?",sub:"Lost in Berlin, directions, articles, jaywalking",icon:"\uD83D\uDDFA\uFE0F",level:"A1.1",color:"#7B5EE8",lessons:[
// --- L1: Rosa Himmel uber Berlin (Story Intro) ---
{id:"deu_r2l1",title:"Rosa Himmel über Berlin",icon:"\uD83C\uDF05",xp:15,board:true,steps:[
{type:"intro",title:"Rosa Himmel über Berlin",desc:"Verumius stands at the Brandenburger Tor with an upside-down map. Pink dawn light. German street names everywhere. Time to learn the city.",goals:["Learn Berlin landmarks and places","Master first direction words","Understand noun genders through articles"]},
{type:"teach",trg:"die Straße",src:"the street",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Straßen.",example:"A: Wie heißt diese Straße?\nB: Das ist die Friedrichstraße.",exampleSrc:"A: What is this street called?\nB: This is Friedrichstraße.",funFact:"Germany has about 650,000 streets. The longest street name? Bischofszeller Straße. The ß (Eszett) is unique to German."},
{type:"teach",trg:"der Platz",src:"the square, plaza",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Plätze.",example:"A: Wo ist der Alexanderplatz?\nB: Der Alexanderplatz ist dort drüben.",exampleSrc:"A: Where is Alexanderplatz?\nB: Alexanderplatz is over there.",funFact:"Alexanderplatz was named after Russian Tsar Alexander I. Berliners call it 'Alex.' Every German city has a central Platz."},
{type:"teach",trg:"die Brücke",src:"the bridge",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Brücken.",example:"A: Die Brücke ist schön!\nB: Ja, Berlin hat viele Brücken.",exampleSrc:"A: The bridge is beautiful!\nB: Yes, Berlin has many bridges.",funFact:"Berlin has more bridges than Venice. About 1,700! The Oberbaumbrücke is the most famous, connecting Kreuzberg and Friedrichshain."},
{type:"teach",trg:"die Kirche",src:"the church",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Kirchen.",example:"A: Ist das eine Kirche?\nB: Ja, das ist die Gedächtniskirche.",exampleSrc:"A: Is that a church?\nB: Yes, that is the Memorial Church.",funFact:"The Kaiser-Wilhelm-Gedächtniskirche was deliberately left half-ruined after WWII as a peace memorial. Berliners call it 'der hohle Zahn' (the hollow tooth)."},
{type:"teach",trg:"das Rathaus",src:"the city hall",pos:"noun",gender:"n",note:"Neuter noun. Compound: Rat (council) + Haus (house).",example:"A: Wo ist das Rathaus?\nB: Das Rathaus ist am Alexanderplatz.",exampleSrc:"A: Where is city hall?\nB: City hall is at Alexanderplatz.",funFact:"Berlin's Rathaus is called 'Rotes Rathaus' because of its red bricks, not its politics. Compound nouns take the gender of the LAST word: Haus = das."},
{type:"match",pairs:[{trg:"der Platz",src:"the square, plaza"},{trg:"die Brücke",src:"the bridge"},{trg:"die Kirche",src:"the church"},{trg:"das Rathaus",src:"the city hall"}]},
{type:"teach",trg:"links",src:"left",pos:"adv",gender:null,note:"Direction word. No gender (adverb).",example:"A: Wohin gehe ich?\nB: Gehen Sie links.",exampleSrc:"A: Where do I go?\nB: Go left.",funFact:"In old Germanic tradition, 'links' was considered the unlucky side. Left-handers were once forced to switch hands. The word is related to 'link' (sly/cunning)."},
{type:"mc",q:"'Das Rathaus' hat welches Geschlecht?",opts:["neutral (das)","Plural (die)","maskulin (der)","feminin (die)"],ans:"neutral (das)",hint:"Compound nouns take the gender of the last word. Haus is neuter."},
{type:"teach",trg:"rechts",src:"right",pos:"adv",gender:null,note:"Direction word. No gender (adverb).",example:"A: Ist die Apotheke rechts?\nB: Ja, rechts an der Ecke.",exampleSrc:"A: Is the pharmacy on the right?\nB: Yes, on the right at the corner.",funFact:"'Recht' also means 'right/correct' and 'law.' Rechts = right in every sense. 'Das Recht' = the law. 'Du hast recht' = you are right."},
{type:"teach",trg:"geradeaus",src:"straight ahead",pos:"adv",gender:null,note:"Direction word. Compound: gerade (straight) + aus (out).",example:"A: Wo ist der Bahnhof?\nB: Immer geradeaus!",exampleSrc:"A: Where is the station?\nB: Straight ahead!",funFact:"Germans love building compound direction words. Geradeaus = straight-out. You will hear this more than any other direction word."},
{type:"teach",trg:"wohin",src:"where to",pos:"adv",gender:null,note:"Question word for direction/destination.",example:"A: Wohin fährst du?\nB: Ich fahre nach Berlin.",exampleSrc:"A: Where are you going?\nB: I am going to Berlin.",funFact:"German splits 'where' into three: wo (where at), woher (where from), wohin (where to). English lost this precision centuries ago."},
{type:"tip",title:"Gender Color Code",text:"Every German noun has a gender. Watch the colors on every word card:\n\nder = blue (masculine)\ndie = crimson (feminine)\ndas = green (neuter)\n\nYour brain will start seeing patterns. Trust the colors.",deepDive:{title:"Why does German have three genders?",text:"Proto-Germanic had three genders, inherited from Proto-Indo-European. Most modern Germanic languages reduced this: English dropped all three, Dutch merged to two (de/het), Swedish and Danish use two (en/ett).\n\nGerman kept all three. This is one reason German is harder for English speakers than Dutch or Swedish.\n\nThe good news: you only need to assign the right article to the right noun. You do not need to understand WHY Mädchen (girl) is neuter or why Sonne (sun) is feminine. Just learn the word with its article every time."}},
{type:"mc",q:"Verumius needs to go straight. Which direction word?",opts:["wohin","geradeaus","links","rechts"],ans:"geradeaus",hint:"This compound word means 'straight-out.'"},
{type:"fb",s:"Die Kirche ist {1}, nicht rechts.",a:["links"],opts:["links","geradeaus","wohin","hier"],hint:"The opposite of rechts (right) is...",sSrc:"The church is to the left, not right."},
{type:"mc",q:"What is the gender of 'Rathaus'?",opts:["masculine (der)","feminine (die)","neuter (das)","plural (die)"],ans:"neuter (das)",hint:"Compound nouns borrow the gender of their final component. What gender is the last part of Rathaus?"},
{type:"match",pairs:[{trg:"die Straße",src:"street"},{trg:"der Platz",src:"square"},{trg:"die Brücke",src:"bridge"},{trg:"die Kirche",src:"church"},{trg:"das Rathaus",src:"city hall"}]},
{type:"fb",s:"Berlin hat viele {1}. Die Oberbaumbrücke ist berühmt.",a:["Brücken"],opts:["Brücken","Straßen","Plätze","Kirchen"],hint:"Structures that cross rivers or canals. Berlin has 1,700 of them.",sSrc:"Berlin has many bridges. The Oberbaumbrücke is famous."},
{type:"mc",q:"German splits 'where' into three words. Which asks about direction?",opts:["wo","woher","warum","wohin"],ans:"wohin",hint:"This question word asks WHERE TO, not where at or where from."}]},
// --- L2: Die Stadt erkunden (Vocab: Places + Transport) ---
{id:"deu_r2l2",title:"Die Stadt erkunden",icon:"\uD83C\uDFD9\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Die Stadt erkunden",desc:"Learn the places you will see (and get lost trying to find) in a German city. Every noun comes with its article and gender color.",goals:["Learn 30+ place and transport words","Recognize noun gender patterns","Navigate a German city with confidence"]},
{type:"teach",trg:"die Stadt",src:"the city / town",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Städte (note the umlaut!).\nOne of the most common German nouns. Used in many compounds.",example:"A: Gefällt dir die Stadt?\nB: Ja, Berlin ist eine tolle Stadt!\nA: Welche Stadt in Deutschland magst du am liebsten?",exampleSrc:"A: Do you like the city?\nB: Yes, Berlin is a great city!\nA: Which city in Germany do you like the most?",funFact:"German builds dozens of compounds from Stadt: Innenstadt (city center), Stadtplan (city map), Hauptstadt (capital city), Altstadt (old town), Stadtrat (city council). Learn Stadt and you unlock them all."},
{type:"teach",trg:"die Apotheke",src:"the pharmacy",pos:"noun",gender:"f",note:"Feminine noun. Marked with a red A symbol.",example:"A: Ich brauche Medizin. Wo ist die Apotheke?\nB: Die Apotheke ist um die Ecke.",exampleSrc:"A: I need medicine. Where is the pharmacy?\nB: The pharmacy is around the corner.",funFact:"German pharmacies sell medicine only. For shampoo, toothpaste, or vitamins, you need a Drogerie (like dm or Rossmann). Two different shops!"},
{type:"teach",trg:"die Ecke",src:"the corner",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Ecken.\nUsed in directions: um die Ecke = around the corner.",example:"A: Wo ist die Bäckerei?\nB: Gleich um die Ecke, links.",exampleSrc:"A: Where is the bakery?\nB: Just around the corner, on the left.",funFact:"An Eckhaus is a corner building, the most coveted location for shops. An Eckkneipe is a corner pub, a Berlin institution."},
{type:"teach",trg:"das Hotel",src:"the hotel",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Hotels.\nSame word internationally. German pronunciation: ho-TEL.",example:"A: Wo übernachtest du?\nB: Im Hotel am Bahnhof.",exampleSrc:"A: Where are you staying?\nB: In the hotel at the train station.",funFact:"Germany has around 35,000 hotels. The word comes from French hotel, which originally meant a large townhouse, not a place for overnight guests."},
{type:"teach",trg:"die Post",src:"the post office",pos:"noun",gender:"f",note:"Feminine noun. No common plural in this sense.\nAlso means mail or post in general.",example:"A: Wo ist die Post?\nB: Die Post ist neben der Bank.",exampleSrc:"A: Where is the post office?\nB: The post office is next to the bank.",funFact:"Deutsche Post (German Post) was founded in 1490 as a royal mail service. The yellow color of German postboxes and Post offices dates back to the Prussian era."},
{type:"match",pairs:[{trg:"die Apotheke",src:"the pharmacy"},{trg:"die Ecke",src:"the corner"},{trg:"das Hotel",src:"the hotel"},{trg:"die Post",src:"the post office"}]},
{type:"teach",trg:"die Polizei",src:"the police",pos:"noun",gender:"f",note:"Feminine noun. No plural (collective noun).\nCall 110 in Germany for the police.",example:"A: Ich brauche Hilfe. Wo ist die Polizei?\nB: Das Polizeirevier ist am Platz.",exampleSrc:"A: I need help. Where is the police?\nB: The police station is at the square.",funFact:"The German emergency number for police is 110. For fire and ambulance it is 112. Both numbers work across the EU."},
{type:"fb",s:"Wo ist die {1}? Ich brauche Medizin.",a:["Apotheke"],opts:["Apotheke","Post","Bank","Polizei"],hint:"You need medicine, so which place sells it?",sSrc:"Where is the pharmacy? I need medicine."},
{type:"teach",trg:"die Bank",src:"the bank",pos:"noun",gender:"f",note:"Feminine noun. Also means 'the bench'!",example:"A: Wo ist die Bank?\nB: Die Bank ist neben dem Hotel.",exampleSrc:"A: Where is the bank?\nB: The bank is next to the hotel.",funFact:"Die Bank means both 'the bank' and 'the bench.' Context tells you which. At a park, it is a bench. On a street with glass doors, it is a bank."},
{type:"teach",trg:"die Bibliothek",src:"the library",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'bibliotheke.'",example:"A: Hast du ein Buch?\nB: Nein, ich gehe in die Bibliothek.",exampleSrc:"A: Do you have a book?\nB: No, I am going to the library.",funFact:"Berlin's Staatsbibliothek has over 11 million books. The word comes from Greek: biblion (book) + theke (storage). Same root as 'Bible.'"},
{type:"teach",trg:"die Bäckerei",src:"the bakery",pos:"noun",gender:"f",note:"Feminine noun. The -ei ending is ALWAYS feminine.",example:"A: Wo kaufst du Brot?\nB: In der Bäckerei natürlich!",exampleSrc:"A: Where do you buy bread?\nB: At the bakery, of course!",funFact:"Germany has about 11,000 bakeries. That is more than McDonald's, Burger King, and Starbucks combined. Words ending in -ei are always feminine (die)."},
{type:"teach",trg:"das Café",src:"the cafe",pos:"noun",gender:"n",note:"Neuter noun. das Café = the place, der Kaffee = the drink.",example:"A: Gehen wir ins Café?\nB: Ja, ich möchte einen Kaffee.",exampleSrc:"A: Shall we go to the cafe?\nB: Yes, I would like a coffee.",funFact:"das Café = the place where you drink. der Kaffee = the drink itself. Different genders, different meanings. Berlin has over 2,000 cafes."},
{type:"teach",trg:"das Geschäft",src:"the shop, store, business",pos:"noun",gender:"n",note:"Neuter noun. More formal than 'Laden.'",example:"A: Ist das Geschäft noch auf?\nB: Nein, es ist geschlossen.",exampleSrc:"A: Is the store still open?\nB: No, it is closed.",funFact:"Geschäft means both 'shop' and 'business.' A Geschäftsmann is a businessman. A Geschäftsfrau is a businesswoman. German loves transparent compounds."},
{type:"mc",q:"Wo kaufst du Brot?",opts:["in der Bäckerei","in der Bibliothek","im Café","in der Bank"],ans:"in der Bäckerei",hint:"The baker works here. Words ending in -ei are always feminine."},
{type:"teach",trg:"die Innenstadt",src:"the city center",pos:"noun",gender:"f",note:"COMPOUND: Innen (inner) + Stadt (city).\nFeminine noun. Compound: Innen (inner) + Stadt (city).",example:"A: Wo ist die Innenstadt?\nB: Die Innenstadt ist am Alexanderplatz.",exampleSrc:"A: Where is the city center?\nB: The city center is at Alexanderplatz.",funFact:"Literally 'inner city.' Germans build nouns by stacking: Innen + Stadt. The gender follows the last word: Stadt = die."},
{type:"teach",trg:"das Kino",src:"the cinema",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'kinema' (movement).",example:"A: Was läuft im Kino?\nB: Ein deutscher Film!",exampleSrc:"A: What is playing at the cinema?\nB: A German film!",funFact:"Germans say 'Wir gehen ins Kino' even when they mean streaming at home. Berlin hosts the Berlinale, one of the world's biggest film festivals."},
{type:"teach",trg:"der Markt",src:"the market",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Märkte.",example:"A: Wann ist der Markt?\nB: Der Markt ist am Samstag.",exampleSrc:"A: When is the market?\nB: The market is on Saturday.",funFact:"Every German town has a weekly Wochenmarkt. Berlin's Turkish Market on the Maybachufer is legendary for fresh produce and street food."},
{type:"match",pairs:[{trg:"die Stadt",src:"the city"},{trg:"das Hotel",src:"the hotel"},{trg:"die Post",src:"the post office"},{trg:"das Kino",src:"the cinema"}]},
{type:"mc",q:"You need bread. Which place do you look for?",opts:["die Apotheke","die Bäckerei","die Bank","die Bibliothek"],ans:"die Bäckerei",hint:"Think of Bäcker (baker). Where does a baker work?"}
]},

// ─── Lesson: Geschäfte und Verkehr ───
{id:"deu_r2l3",title:"Geschäfte und Verkehr",icon:"🚇",xp:15,board:true,steps:[
{type:"intro",title:"Geschäfte und Verkehr",desc:"From shops and restaurants to subways and bicycles: learn how to get around Berlin and find what you need. Plus the city map, bus stops, and intersections.",goals:["Learn vocabulary for shops and restaurants","Master transport vocabulary: U-Bahn, S-Bahn, Fahrrad","Navigate with Stadtplan, Haltestelle, and Kreuzung"]},
{type:"teach",trg:"der Laden",src:"the shop (casual)",pos:"noun",gender:"m",note:"Masculine noun. More casual than Geschäft.",example:"A: Kennst du den Laden?\nB: Ja, der Laden ist gut.",exampleSrc:"A: Do you know that shop?\nB: Yes, the shop is good.",funFact:"Laden feels small and personal. Geschäft feels professional and formal. A family bookshop is a Laden. A department store is a Geschäft."},
{type:"teach",trg:"das Restaurant",src:"the restaurant",pos:"noun",gender:"n",note:"Neuter noun. Pronounced res-toh-RAHNG.",example:"A: Gehen wir ins Restaurant?\nB: Ja, ich habe Hunger!",exampleSrc:"A: Shall we go to the restaurant?\nB: Yes, I am hungry!",funFact:"Pronounced more German than French: res-toh-RAHNG. Tipping in Germany is usually 5-10%, not the 15-20% Americans expect."},
{type:"teach",trg:"das Schloss",src:"the castle, palace",pos:"noun",gender:"n",note:"Neuter noun. Also means 'lock'!",example:"A: Ist das ein Schloss?\nB: Ja, das Schloss Charlottenburg.",exampleSrc:"A: Is that a castle?\nB: Yes, Charlottenburg Palace.",funFact:"Das Schloss means both 'the castle' and 'the lock.' Context saves you. Germany has over 20,000 castles and palaces."},
{type:"teach",trg:"das Auto",src:"the car",pos:"noun",gender:"n",note:"Neuter noun. Short for Automobil.",example:"A: Hast du ein Auto?\nB: Nein, ich fahre mit dem Bus.",exampleSrc:"A: Do you have a car?\nB: No, I take the bus.",funFact:"Germany invented the automobile. Karl Benz built the first one in 1886. The Autobahn has sections with no speed limit. Germans take driving very seriously."},
{type:"mc",q:"Hast du ein Auto?",opts:["Nein, ich fahre mit dem Bus.","Ja, ich habe eine Kirche.","Nein, ich esse ein Auto.","Ja, ich kaufe ein Schloss."],ans:"Nein, ich fahre mit dem Bus.",hint:"A reasonable response about not having a car would mention alternative transport."},
{type:"teach",trg:"die U-Bahn",src:"the subway",pos:"noun",gender:"f",note:"Feminine noun. U = Untergrund (underground).",example:"A: Nehmen wir die U-Bahn?\nB: Ja, die U-Bahn ist schnell.",exampleSrc:"A: Shall we take the subway?\nB: Yes, the subway is fast.",funFact:"U = Untergrund. Berlin's first U-Bahn line opened in 1902. Today there are 10 lines and 175 stations. The yellow trains are iconic."},
{type:"teach",trg:"die S-Bahn",src:"the city train",pos:"noun",gender:"f",note:"Feminine noun. S = Schnell (fast) or Stadt (city).",example:"A: Die S-Bahn kommt in zwei Minuten.\nB: Gut, wir nehmen die S-Bahn.",exampleSrc:"A: The S-Bahn comes in two minutes.\nB: Good, we will take the S-Bahn.",funFact:"S-Bahn runs above ground through the city. Berlin's S-Bahn ring circles the center. Together with U-Bahn, it forms one of Europe's best transit networks."},
{type:"teach",trg:"das Fahrrad",src:"the bicycle",pos:"noun",gender:"n",note:"Neuter noun. Compound: Fahr (drive) + Rad (wheel).",example:"A: Fährst du mit dem Fahrrad?\nB: Ja, ich fahre jeden Tag.",exampleSrc:"A: Do you ride a bicycle?\nB: Yes, I ride every day.",funFact:"Fahr + Rad = drive-wheel. Berlin has over 1,000 km of bike paths. Many Berliners use a Fahrrad as their main transport."},
{type:"match",pairs:[{trg:"die Apotheke",src:"pharmacy"},{trg:"das Café",src:"cafe"},{trg:"der Markt",src:"market"},{trg:"die Bäckerei",src:"bakery"},{trg:"das Kino",src:"cinema"},{trg:"die U-Bahn",src:"subway"}]},
{type:"teach",trg:"der Stadtplan",src:"the city map",pos:"noun",gender:"m",note:"COMPOUND: Stadt (city) + Plan (map).\nMasculine noun. Compound: Stadt (city) + Plan (plan).",example:"A: Hast du einen Stadtplan?\nB: Ja, aber er ist falsch herum!",exampleSrc:"A: Do you have a city map?\nB: Yes, but it is upside down!",funFact:"Stadt + Plan. Verumius should have used a better one. Compound nouns take the gender of the last word: Plan = der."},
{type:"teach",trg:"der Eingang",src:"the entrance",pos:"noun",gender:"m",note:"Masculine noun. Ein (in) + Gang (walk).",example:"A: Wo ist der Eingang?\nB: Der Eingang ist dort.",exampleSrc:"A: Where is the entrance?\nB: The entrance is there.",funFact:"Ein + Gang = in-walk. The exit? Ausgang = out-walk. Germany loves building logical compound nouns."},
{type:"teach",trg:"die Haltestelle",src:"the bus/tram stop",pos:"noun",gender:"f",note:"COMPOUND: Halte (stop) + Stelle (place).\nFeminine noun. Halte (stop) + Stelle (place).",example:"A: Ist hier eine Haltestelle?\nB: Ja, die Haltestelle ist dort.",exampleSrc:"A: Is there a stop here?\nB: Yes, the stop is over there.",funFact:"Halte + Stelle = stop-place. Every German city marks its Haltestellen with a green H sign."},
{type:"teach",trg:"die Kreuzung",src:"the intersection",pos:"noun",gender:"f",note:"COMPOUND: Kreuz (cross) + ung (noun suffix).\nFeminine noun. From Kreuz (cross). The -ung ending = always die.",example:"A: An der Kreuzung links abbiegen.\nB: Danke!",exampleSrc:"A: Turn left at the intersection.\nB: Thanks!",funFact:"From Kreuz (cross). Where streets cross. The -ung ending is ALWAYS feminine: die Kreuzung, die Richtung, die Verbindung."},
{type:"tip",title:"Gender Patterns",text:"Words ending in -ung, -ei, -keit, -heit, -ie are ALWAYS feminine (die).\nWords ending in -chen are ALWAYS neuter (das).\nCompound nouns take the gender of the LAST word.\nThese rules cover hundreds of nouns.",deepDive:{title:"The -tion rule and loanwords",text:"German borrowed thousands of words from Latin and French. Nouns ending in -tion (Station, Nation, Organisation) are ALL feminine (die).\n\nSimilarly:\n-tät (Qualität, Universität) = always die\n-ik (Musik, Physik) = usually die\n-ismus (Tourismus, Idealismus) = always der\n-ment (Instrument, Moment) = usually das\n\nKnowing these suffix rules handles a large proportion of technical and academic vocabulary without memorization."}},
{type:"teach",trg:"die Verbindung",src:"the connection",pos:"noun",gender:"f",note:"Feminine -ung noun. From verbinden (to connect).",example:"A: Gibt es eine Verbindung nach Hamburg?\nB: Ja, um 14 Uhr.",exampleSrc:"A: Is there a connection to Hamburg?\nB: Yes, at 2 PM.",funFact:"In public transport, Verbindung means a route or connection between stops."},
{type:"mc",q:"Which word means 'connection' for transit?",opts:["die Kreuzung","die Verbindung","die Haltestelle","der Bahnsteig"],ans:"die Verbindung",hint:"The -ung ending tells you it is feminine. This word is about connecting routes."},
{type:"mc",q:"You need medicine. You look for...",opts:["die Bäckerei","die Bank","die Apotheke","das Café"],ans:"die Apotheke",hint:"The red A symbol marks these in Germany."}]},
// --- L3: Entschuldigung, können Sie mir helfen? (Story Dev) ---
{id:"deu_r2l4",title:"Können Sie mir helfen?",icon:"\uD83D\uDE4B",xp:15,board:true,steps:[
{type:"intro",title:"Können Sie mir helfen?",desc:"Verumius has a map but no phone signal. Time to ask actual humans for help. In German. With formal address.",goals:["Learn modal verbs können/müssen/dürfen","Master polite request phrases","Survive the jaywalking incident"]},
{type:"teach",trg:"können",src:"can, to be able to",pos:"aux",gender:null,note:"Modal verb. Ich kann, du kannst, er kann, wir können.",example:"A: Können Sie mir helfen?\nB: Ja, natürlich!",exampleSrc:"A: Can you help me?\nB: Yes, of course!",funFact:"'Können Sie...?' is the magic phrase that opens every polite request in German. Learn this before anything else."},
{type:"teach",trg:"müssen",src:"must, to have to",pos:"aux",gender:null,note:"Modal verb. Ich muss, du musst, er muss, wir müssen.",example:"A: Ich muss zum Bahnhof.\nB: Der Bahnhof ist geradeaus.",exampleSrc:"A: I must get to the station.\nB: The station is straight ahead.",funFact:"Unlike English 'must,' German müssen is just neutral obligation. 'Ich muss gehen' means 'I have to go,' not a dramatic declaration."},
{type:"teach",trg:"dürfen",src:"may, to be allowed to",pos:"aux",gender:null,note:"Modal verb. Ich darf, du darfst, er darf, wir dürfen.",example:"A: Darf ich fragen?\nB: Ja, natürlich dürfen Sie!",exampleSrc:"A: May I ask?\nB: Yes, of course you may!",funFact:"'Darf ich?' (May I?) is the German politeness superpower. Use it before touching, asking, or entering. It never fails."},
{type:"teach",trg:"möchten",src:"would like",pos:"aux",gender:null,note:"Polite form. Ich möchte, du möchtest, er möchte.",example:"A: Was möchten Sie?\nB: Ich möchte einen Kaffee, bitte.",exampleSrc:"A: What would you like?\nB: I would like a coffee, please.",funFact:"Technically a subjunctive of mögen. Germans use möchten much more than 'ich will' (which sounds demanding). Möchten is the polite choice."},
{type:"teach",trg:"doch",src:"yes! (contradicting a negative), indeed",pos:"part",gender:null,note:"Untranslatable particle. Contradicts a negative statement.",example:"A: Du sprichst kein Deutsch!\nB: Doch! Ein bisschen!",exampleSrc:"A: You don't speak German!\nB: Yes I do! A little!",funFact:"Untranslatable! Someone says 'You can't.' You say 'Doch!' = 'Yes I CAN!' English has no single word for this. Germans use it constantly."},
{type:"tip",title:"Doch: The Contradictor",text:"German has a special word for contradicting a negative:\n\nA: Du kommst nicht? (You are not coming?)\nB: Doch! Ich komme. (Yes I am! I am coming.)\n\nDoch = yes (but I disagree with your negative assumption)\nJa = yes (regular agreement)\nNein = no\n\nIf you say 'ja' to a negative question, the meaning is unclear in German. Doch removes all ambiguity.",deepDive:{title:"Why German needs doch",text:"Many languages have a third answer word for contradicting negatives. French has 'si', German has 'doch', Dutch has 'toch' (in some uses) or 'jawel'.\n\nEnglish lost this word. When someone says 'You didn't eat, did you?' and you DID eat, English speakers say 'Yes I did!' with heavy stress. German uses one word: Doch.\n\nDoch has many other uses in German (e.g., as a softener, in commands, in exclamations). For now, master the contradiction function."}},
{type:"teach",trg:"mal",src:"just, once (softener)",pos:"part",gender:null,note:"Makes requests sound friendlier and less demanding.",example:"A: Schau mal!\nB: Was ist das?",exampleSrc:"A: Just look!\nB: What is that?",funFact:"'Schau mal' = just look. 'Sag mal' = tell me. Mal makes everything sound friendlier. Without it, commands sound harsh."},
{type:"teach",trg:"nach",src:"to (cities/countries), after",pos:"prep",gender:null,note:"Preposition with multiple meanings.",example:"A: Ich fahre nach Berlin.\nB: Wann fährst du?",exampleSrc:"A: I am going to Berlin.\nB: When are you going?",funFact:"'Nach Berlin' = to Berlin. 'Nach links' = to the left. 'Nach dem Essen' = after the meal. One little word, enormous reach."},
{type:"teach",trg:"zu",src:"to (specific places/people)",pos:"prep",gender:null,note:"Preposition. 'Zum' = zu + dem, 'Zur' = zu + der.",example:"A: Ich gehe zum Bahnhof.\nB: Der Bahnhof ist nicht weit.",exampleSrc:"A: I am going to the station.\nB: The station is not far.",funFact:"'Zu' for specific places: zum Bahnhof, zur Apotheke. 'Nach' for cities/countries: nach Berlin. This distinction does not exist in English."}]},
{id:"deu_r2l4b",title:"Können Sie mir helfen? (Teil 2)",icon:"\uD83D\uDE4B",xp:15,board:true,steps:[
{type:"intro",title:"Können Sie mir helfen? (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"neben",src:"next to, beside",pos:"prep",gender:null,note:"Preposition of location.",example:"A: Wo ist die Bank?\nB: Die Bank ist neben der Apotheke.",exampleSrc:"A: Where is the bank?\nB: The bank is next to the pharmacy.",funFact:"'Die Bank ist neben der Apotheke.' Neben = physically beside something. Very useful for giving directions."},
{type:"teach",trg:"geben",src:"to give",pos:"verb",gender:null,note:"Irregular: ich gebe, du gibst, er gibt.",example:"A: Können Sie mir den Stadtplan geben?\nB: Ja, hier bitte!",exampleSrc:"A: Can you give me the city map?\nB: Yes, here you go!",funFact:"'Es gibt' = there is/are (literally 'it gives'). 'Es gibt viele Cafés in Berlin' = There are many cafes in Berlin. One of German's most common phrases."},
{type:"verb_table",title:"geben (to give)",groups:[{label:"Present tense (stem change: e → i)",rows:[{pronoun:"ich",form:"gebe",src:"I give"},{pronoun:"du",form:"gibst",src:"you give"},{pronoun:"er/sie/es",form:"gibt",src:"he/she/it gives"},{pronoun:"wir",form:"geben",src:"we give"},{pronoun:"ihr",form:"gebt",src:"you all give"},{pronoun:"sie/Sie",form:"geben",src:"they/you (formal) give"}]}],note:"Key phrase: es gibt = there is/are. Literally: it gives."},
{type:"teach",trg:"zeigen",src:"to show, to point",pos:"verb",gender:null,note:"Regular verb. Very useful for directions.",example:"A: Können Sie mir den Weg zeigen?\nB: Ja, geradeaus und dann links.",exampleSrc:"A: Can you show me the way?\nB: Yes, straight ahead then left.",funFact:"'Können Sie mir zeigen?' = Can you show me? Point and ask. This gets you anywhere in Germany."},
{type:"teach",trg:"lesen",src:"to read",pos:"verb",gender:null,note:"Irregular: ich lese, du liest, er liest.",example:"A: Kannst du das lesen?\nB: Ja, das ist Deutsch!",exampleSrc:"A: Can you read that?\nB: Yes, that is German!",funFact:"Irregular: the vowel changes from e to ie in du/er forms. Ich lese, du liest. German and English 'read' share the same ancient root."},
{type:"teach",trg:"sehen",src:"to see",pos:"verb",gender:null,note:"Irregular stem change e→ie: ich sehe, du siehst, er sieht.",example:"A: Siehst du das Schild?\nB: Ja, ich sehe es!",exampleSrc:"A: Do you see the sign?\nB: Yes, I see it!",funFact:"One of German's most common irregular verbs. 'Auf Wiedersehen' literally means 'until seeing again.' The stem change e→ie applies in du and er/sie/es forms only."},
{type:"verb_table",title:"lesen (to read)",groups:[{label:"Present tense (stem change: e → ie)",rows:[{pronoun:"ich",form:"lese",src:"I read"},{pronoun:"du",form:"liest",src:"you read"},{pronoun:"er/sie/es",form:"liest",src:"he/she/it reads"},{pronoun:"wir",form:"lesen",src:"we read"},{pronoun:"ihr",form:"lest",src:"you all read"},{pronoun:"sie/Sie",form:"lesen",src:"they/you (formal) read"}]}],note:"Stem vowel e changes to ie in du and er/sie/es. Same pattern: empfehlen (empfiehlt)."},
{type:"teach",trg:"hören",src:"to hear",pos:"verb",gender:null,note:"Regular verb. Zuhören = to listen actively.",example:"A: Hörst du die Musik?\nB: Ja, ich höre sie!",exampleSrc:"A: Do you hear the music?\nB: Yes, I hear it!",funFact:"Hören = to hear passively. Zuhören = to listen actively. 'Hör zu!' = Listen! Adding zu changes passive hearing to active listening."},
{type:"teach",trg:"verstehen",src:"to understand",pos:"verb",gender:null,note:"Inseparable prefix verb: ver + stehen.",example:"A: Verstehen Sie mich?\nB: Ja, ich verstehe!",exampleSrc:"A: Do you understand me?\nB: Yes, I understand!",funFact:"Ver + stehen = to stand before something mentally. 'Ich verstehe' is one of the most useful sentences you will ever learn in German."},
{type:"tip",title:"Jaywalking in Germany",text:"In Germany, crossing on a red light is genuinely frowned upon, especially if children are watching. You might get a lecture from a complete stranger. It is not law enforcement people fear. It is social judgment. Verumius learned this the hard way."},
{type:"mc",q:"Verumius asks for help. Which is most polite?",opts:["Können Sie mir helfen?","Hilf mir!","Wo ist das?","Gib mir den Weg!"],ans:"Können Sie mir helfen?",hint:"Polite requests use a modal verb with the formal pronoun."},
{type:"mc",q:"Someone says 'Du sprichst kein Deutsch.' You DO speak German. You reply:",opts:["Ja!","Doch!","Bitte!","Nein!"],ans:"Doch!",hint:"This special word contradicts a negative statement."},
{type:"fb",s:"Entschuldigung, {1} Sie mir bitte den Weg zeigen?",a:["können"],opts:["können","müssen","dürfen","möchten"],hint:"Which modal expresses ability and polite requests?",sSrc:"Excuse me, can you please show me the way?"},
{type:"mc",q:"Was bedeutet 'lesen'?",opts:["next to, beside","to see","to read","to hear"],ans:"to read",hint:"You do this with a book or newspaper. Related to English 'lesson.'"},
{type:"fb",s:"Wie sagt man 'to see' auf Deutsch? {1}",a:["sehen"],opts:["mal","geben","zu","sehen"],hint:"This verb for visual perception is an irregular strong verb. Ich sehe, du siehst...",sSrc:"How do you say 'to see' in German?"},
{type:"mc",q:"Was bedeutet 'hören'?",opts:["to read","to show, to point","would like","to hear"],ans:"to hear",hint:"You do this with your ears. Think of 'Kopfhörer' (headphones)."},
{type:"fb",s:"{1} Sie mich?",a:["verstehen"],opts:["dürfen","sehen","zeigen","verstehen"],hint:"The verb for comprehension. 'Ver-' prefix + 'stehen' (to stand) = to understand.",sSrc:"Do you understand me?"}
]},
// --- L4: Der, die, das (Grammar) ---
{id:"deu_r2l5",title:"Der, die, das",icon:"\uD83D\uDD24",xp:15,board:true,steps:[
{type:"intro",title:"Der, die, das: Das Artikelmonster",desc:"The German article system: three genders, one monster. But there are patterns that make it learnable.",goals:["Master definite articles (der/die/das)","Learn indefinite articles (ein/eine)","Discover noun gender patterns"]},
{type:"tip",title:"The Nominative Case",text:"The subject of a sentence (who/what DOES the action) uses the nominative case.\n\nder Mann sieht = the man sees\ndie Frau steht = the woman stands\ndas Kind spielt = the child plays\n\nNominative articles: der (masculine), die (feminine), das (neuter), die (plural)."},
{type:"tip",title:"Inversion for Yes/No Questions",text:"In German, to ask a yes/no question, you swap the subject and verb:\n\nDu hast einen Bruder. (statement)\nHast du einen Bruder? (question)\n\nSie sprechen Deutsch. (statement)\nSprechen Sie Deutsch? (question)\n\nEr wohnt in Berlin. (statement)\nWohnt er in Berlin? (question)\n\nThis inversion rule applies to ALL German verbs.",deepDive:{title:"Two types of German questions",text:"German has two question types with different word order:\n\n1. Yes/No questions: Verb first, then subject.\nHast du eine Fahrkarte? (Do you have a ticket?)\n\n2. W-questions: W-word first, verb second, then subject.\nWo hast du eine Fahrkarte? (Where do you have a ticket?)\n\nBoth types put the verb very early. In statements, the verb is in position 2. In yes/no questions, it moves to position 1."}},
{type:"teach",trg:"groß",src:"big, tall, great",pos:"adj",gender:null,note:"Predicative adjective. No ending after 'sein' (to be).",example:"A: Die Stadt ist groß.\nB: Ja, sehr groß.",exampleSrc:"A: The city is big.\nB: Yes, very big.",funFact:"Deutschland means 'land of the people.' Deutsch originally meant 'of the people' in Old High German."},
{type:"teach",trg:"klein",src:"small, little",pos:"adj",gender:null,note:"Predicative adjective. Opposite of groß.",example:"A: Die Bäckerei ist klein.\nB: Ja, aber das Brot ist gut!",exampleSrc:"A: The bakery is small.\nB: Yes, but the bread is good!",funFact:"'Klein aber fein' = small but fine. A beloved German saying about quality over size."},
{type:"teach",trg:"lang",src:"long",pos:"adj",gender:null,note:"For physical length. 'Lange' for time duration.",example:"A: Die Straße ist lang.\nB: Ja, sehr lang!",exampleSrc:"A: The street is long.\nB: Yes, very long!",funFact:"'Lang' for physical length: die Straße ist lang. Add -e for time: 'Wie lange?' = How long (in time)?"},
{type:"teach",trg:"kurz",src:"short (length or time)",pos:"adj",gender:null,note:"Opposite of lang.",example:"A: Ist der Weg kurz?\nB: Ja, nur fünf Minuten.",exampleSrc:"A: Is the way short?\nB: Yes, only five minutes.",funFact:"'Kurz und knapp' = short and concise. Germans value brevity in speech."},
{type:"verb_table",title:"Definite Articles: Nominative",label:"The subject case",groups:[{header:"der/die/das/die",rows:[{pronoun:"Masculine",form:"der",src:"the (masc)"},{pronoun:"Feminine",form:"die",src:"the (fem)"},{pronoun:"Neuter",form:"das",src:"the (neut)"},{pronoun:"Plural",form:"die",src:"the (pl)"}]}]},
{type:"verb_table",title:"Indefinite Articles: Nominative",label:"A/an in the subject case",groups:[{header:"ein/eine/ein",rows:[{pronoun:"Masculine",form:"ein",src:"a (masc)"},{pronoun:"Feminine",form:"eine",src:"a (fem)"},{pronoun:"Neuter",form:"ein",src:"a (neut)"},{pronoun:"Plural",form:"--",src:"(no indefinite plural)"}]}]},
{type:"tip",title:"Suffix Rules: Reliable Gender Signals",text:"ALWAYS die (feminine):\n-ung: die Richtung, die Kreuzung, die Verbindung\n-heit/-keit: die Freiheit, die Möglichkeit\n-schaft: die Freundschaft\n-tion: die Nation, die Station\n-ei: die Bäckerei\n\nALWAYS das (neuter):\n-chen: das Mädchen, das Brötchen\n-lein: das Büchlein\n-um: das Museum\n\nOften der (masculine):\n-er (agent nouns): der Lehrer, der Fahrer\nDays, months, seasons = der\nCompound nouns = gender of LAST word (Stadtplan: Plan = der)",deepDive:{title:"The -tion rule and loanwords",text:"German borrowed thousands of words from Latin and French. Nouns ending in -tion (Station, Nation, Organisation) are ALL feminine (die).\n\nSimilarly:\n-taet (Qualitaet, Universitaet) = always die\n-ik (Musik, Physik) = usually die\n-ismus (Tourismus, Idealismus) = always der\n-ment (Instrument, Moment) = usually das\n\nKnowing these suffix rules handles a large proportion of technical and academic vocabulary without memorization."}},
{type:"teach",trg:"die Frage",src:"the question",pos:"noun",gender:"f",note:"Feminine noun. 'Keine Frage!' = No doubt!",example:"A: Ich habe eine Frage.\nB: Ja, bitte?",exampleSrc:"A: I have a question.\nB: Yes, please?",funFact:"'Keine Frage!' = No question about it! No doubt! Germans say this when something is obviously true."},
{type:"teach",trg:"das Problem",src:"the problem",pos:"noun",gender:"n",note:"Neuter noun. Same as English.",example:"A: Gibt es ein Problem?\nB: Nein, kein Problem!",exampleSrc:"A: Is there a problem?\nB: No, no problem!",funFact:"'Kein Problem!' Same in English and German. One of the easiest words to remember. Always neuter: das Problem."},
{type:"teach",trg:"das Beispiel",src:"the example",pos:"noun",gender:"n",note:"Neuter noun. 'Zum Beispiel' (z.B.) = for example.",example:"A: Kannst du ein Beispiel geben?\nB: Ja, zum Beispiel: der Hund.",exampleSrc:"A: Can you give an example?\nB: Yes, for example: the dog.",funFact:"'Zum Beispiel' (z.B.) = 'for example.' You will see z.B. everywhere in German texts. It is the German equivalent of e.g."},
{type:"mc",q:"___ Apotheke ist neben ___ Hotel.",opts:["Die ... dem","Der ... die","Das ... der","Die ... das"],ans:"Die ... dem",hint:"Apotheke is a feminine noun. Hotel is neuter, and neben takes dative for location."},
{type:"mc",q:"Das Hotel ist ___. (big)",opts:["große","groß","großes","großer"],ans:"groß",hint:"After 'sein' (is), adjectives have NO ending. Just the base form."},
{type:"teach",trg:"schnell",src:"fast, quick",pos:"adj",gender:null,note:"Adjective/adverb. No ending after sein.",example:"A: Ist der Zug schnell?\nB: Ja, der ICE ist sehr schnell!",exampleSrc:"A: Is the train fast?\nB: Yes, the ICE is very fast!",funFact:"Germans on the Autobahn define 'schnell' differently than most humans. Some sections have no speed limit at all."},
{type:"teach",trg:"langsam",src:"slow",pos:"adj",gender:null,note:"Adjective/adverb. Opposite of schnell.",example:"A: Können Sie langsam sprechen?\nB: Ja, ich spreche langsam.",exampleSrc:"A: Can you speak slowly?\nB: Yes, I will speak slowly.",funFact:"'Langsam, bitte!' = Slowly, please! Your survival phrase when Germans talk too fast. You will use this daily."},
{type:"teach",trg:"anfangen",src:"to start, to begin",pos:"verb",gender:null,note:"Separable verb: Ich fange an.",example:"A: Wann fangen wir an?\nB: Wir fangen um neun an.",exampleSrc:"A: When do we start?\nB: We start at nine.",funFact:"Separable: 'Ich fange an.' The 'an' goes to the end. Synonymous with beginnen, but anfangen is more casual."},
{type:"teach",trg:"aufhören",src:"to stop, to quit",pos:"verb",gender:null,note:"Separable verb: Hör auf!",example:"A: Hör auf!\nB: Okay, ich höre auf.",exampleSrc:"A: Stop it!\nB: Okay, I will stop.",funFact:"Separable: 'Hör auf!' = Stop it! One of the first commands German kids learn. Auf = up/open, hören = to hear."},
{type:"fb",s:"{1} Straße ist lang und breit.",a:["Die"],opts:["Die","Der","Das","Ein"],hint:"Straße is feminine. Which definite article matches?",sSrc:"The street is long and wide."},
{type:"mc",q:"Which is correct?",opts:["Das Museum ist großes.","Der Museum ist groß.","Das Museum ist groß.","Das Museum ist große."],ans:"Das Museum ist groß.",hint:"This noun is neuter. Predicative adjectives need no ending."},
{type:"drag_fill",s:"{1} Café ist klein, aber {2} Restaurant ist groß.",blanks:{"1":"Das","2":"das"},pool:["Das","das","Der","die","Die"],hint:"Café and Restaurant are both neuter. Sentence-initial gets capital D.",sSrc:"The café is small, but the restaurant is big."},
{type:"mc",q:"Words ending in -ung are always...",opts:["masculine (der)","neuter (das)","depends on the word","feminine (die)"],ans:"feminine (die)",hint:"Richtung, Kreuzung, Verbindung, Besichtigung... all share one article."},

{"type":"mc","q":"Was ist 'die Frage'?","opts":["the question","the answer","the problem","the idea"],"ans":"the question","hint":"The opposite of an answer."},
{"type":"fb","s":"Das ist ein großes {1}.","a":["Problem"],"opts":["Problem","Frage","Antwort","Idee"],"hint":"Something difficult that needs solving.","sSrc":"That is a big problem."},
{"type":"mc","q":"Was bedeutet 'schnell'?","opts":["fast","slow","heavy","light"],"ans":"fast","hint":"The opposite of langsam."},
{"type":"mc","q":"Was bedeutet 'anfangen'?","opts":["to begin","to finish","to forget","to find"],"ans":"to begin","hint":"What you do at the start of something."}]},
// --- L5: Unterwegs in der Stadt (Vocab: Verbs + Adjectives) ---
{id:"deu_r2l6",title:"Unterwegs in der Stadt",icon:"\uD83D\uDEB6",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs in der Stadt",desc:"Verumius wanders Berlin. Every shop, every sign, every scene is a vocabulary lesson. Today: essential verbs and adjectives.",goals:["Learn 30+ everyday verbs","Master descriptive adjectives","Describe places and situations"]},
{type:"tip",title:"No Article with Professions",text:"German drops the article before professions after sein:\n\nIch bin Lehrer. (NOT: Ich bin ein Lehrer)\nSie ist Ärztin. (NOT: Sie ist eine Ärztin)\nEr ist Student. (NOT: Er ist ein Student)\n\nException: if you add an adjective, the article returns:\nEr ist ein sehr guter Lehrer.",deepDive:{title:"Why no article with professions?",text:"Job titles after 'sein' classify the person rather than count them as objects. German omits the article for exactly this reason. The same happens with nationalities (Ich bin Deutsche) and religions. Once an adjective is added, the article returns because a full noun phrase is restored."}},
{type:"teach",trg:"essen",src:"to eat",pos:"verb",gender:null,note:"Irregular: ich esse, du isst, er isst.",example:"A: Was isst du?\nB: Ich esse einen Döner.",exampleSrc:"A: What are you eating?\nB: I am eating a Döner.",funFact:"Irregular: ich esse, du isst. 'Du isst' sounds exactly like 'du ist' (you are). Context saves you every time."},
{type:"verb_table",title:"essen (to eat)",groups:[{label:"Present tense (stem change: e → i)",rows:[{pronoun:"ich",form:"esse",src:"I eat"},{pronoun:"du",form:"isst",src:"you eat"},{pronoun:"er/sie/es",form:"isst",src:"he/she/it eats"},{pronoun:"wir",form:"essen",src:"we eat"},{pronoun:"ihr",form:"esst",src:"you all eat"},{pronoun:"sie/Sie",form:"essen",src:"they/you (formal) eat"}]}],note:"du isst sounds like du ist (you are). Context saves you!"},
{type:"teach",trg:"bestellen",src:"to order",pos:"verb",gender:null,note:"Inseparable prefix verb. Regular conjugation.",example:"A: Ich möchte bestellen.\nB: Was möchten Sie?",exampleSrc:"A: I would like to order.\nB: What would you like?",funFact:"'Ich möchte bestellen' = your restaurant survival phrase. In German restaurants, you often need to actively call the waiter."},
{type:"teach",trg:"bezahlen",src:"to pay",pos:"verb",gender:null,note:"Inseparable prefix verb. Regular.",example:"A: Kann ich bezahlen?\nB: Bar oder mit Karte?",exampleSrc:"A: Can I pay?\nB: Cash or card?",funFact:"Many German shops still prefer cash. 'Nur Bargeld' (cash only) signs are common. Germans love their cash."},
{type:"teach",trg:"kaufen",src:"to buy",pos:"verb",gender:null,note:"Regular verb. Ver+kaufen = to sell.",example:"A: Ich kaufe Brot.\nB: In der Bäckerei?",exampleSrc:"A: I am buying bread.\nB: At the bakery?",funFact:"Kaufen = buy. Verkaufen = sell. The ver- prefix reverses the meaning. Kaufhaus = department store."},
{type:"verb_table",title:"kaufen (to buy)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"kaufe",src:"I buy"},{pronoun:"du",form:"kaufst",src:"you buy"},{pronoun:"er/sie/es",form:"kauft",src:"he/she/it buys"},{pronoun:"wir",form:"kaufen",src:"we buy"},{pronoun:"ihr",form:"kauft",src:"you all buy"},{pronoun:"sie/Sie",form:"kaufen",src:"they/you (formal) buy"}]}],note:"Regular pattern. Einkaufen (separable) = to shop: Ich kaufe ein."},
{type:"teach",trg:"kochen",src:"to cook",pos:"verb",gender:null,note:"Regular verb. Related to Küche (kitchen).",example:"A: Kannst du kochen?\nB: Ja, ich koche gern!",exampleSrc:"A: Can you cook?\nB: Yes, I like to cook!",funFact:"Related to English 'kitchen' (Küche). Both come from Latin 'coquere' (to cook). German kept the K sound."},
{type:"verb_table",title:"kochen (to cook)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"koche",src:"I cook"},{pronoun:"du",form:"kochst",src:"you cook"},{pronoun:"er/sie/es",form:"kocht",src:"he/she/it cooks"},{pronoun:"wir",form:"kochen",src:"we cook"},{pronoun:"ihr",form:"kocht",src:"you all cook"},{pronoun:"sie/Sie",form:"kochen",src:"they/you (formal) cook"}]}],note:"Regular pattern. Der Koch = the cook (noun). Die Küche = the kitchen."},
{type:"teach",trg:"arbeiten",src:"to work",pos:"verb",gender:null,note:"Regular verb. Arbeit = work (noun).",example:"A: Wo arbeitest du?\nB: Ich arbeite in Berlin.",exampleSrc:"A: Where do you work?\nB: I work in Berlin.",funFact:"Arbeit means both 'work' and 'effort/craft.' German workers are protected by some of Europe's strongest labor laws."},
{type:"verb_table",title:"arbeiten (to work)",groups:[{label:"Present tense (regular, -eten verb)",rows:[{pronoun:"ich",form:"arbeite",src:"I work"},{pronoun:"du",form:"arbeitest",src:"you work"},{pronoun:"er/sie/es",form:"arbeitet",src:"he/she/it works"},{pronoun:"wir",form:"arbeiten",src:"we work"},{pronoun:"ihr",form:"arbeitet",src:"you all work"},{pronoun:"sie/Sie",form:"arbeiten",src:"they/you (formal) work"}]}],note:"Verbs ending in -ten/-den add extra -e- in du/er/ihr forms for pronunciation: du arbeitest (not arbeitst)."},
{type:"teach",trg:"besetzt",src:"occupied, taken",pos:"adj",gender:null,note:"Past participle used as adjective.",example:"A: Ist der Platz besetzt?\nB: Ja, leider.",exampleSrc:"A: Is this seat taken?\nB: Yes, unfortunately.",funFact:"'Ist der Platz besetzt?' = Is this seat taken? If you do not ask, Germans will tell you anyway."},
{type:"teach",trg:"geschlossen",src:"closed",pos:"adj",gender:null,note:"Past participle of schließen (to close).",example:"A: Ist das Geschäft auf?\nB: Nein, es ist geschlossen.",exampleSrc:"A: Is the shop open?\nB: No, it is closed.",funFact:"You will see 'geschlossen' on every shop door on Sundays. Germany's Sonntagsruhe (Sunday rest) means most shops close. Bakeries sometimes open Sunday morning."},
{type:"teach",trg:"falsch",src:"wrong, false",pos:"adj",gender:null,note:"Adjective. Opposite of richtig.",example:"A: Ist das richtig?\nB: Nein, das ist falsch!",exampleSrc:"A: Is that correct?\nB: No, that is wrong!",funFact:"'Falsche Richtung!' = Wrong direction! Verumius hears this a lot on his Berlin adventures."},
{type:"teach",trg:"richtig",src:"right, correct",pos:"adj",gender:null,note:"Adjective. Opposite of falsch.",example:"A: Ist das richtig?\nB: Ja, richtig!",exampleSrc:"A: Is that correct?\nB: Yes, correct!",funFact:"'Richtig!' is how Germans say 'Exactly!' in conversation. Short, direct, affirming."},
{type:"mc",q:"Du gehst in eine Bäckerei. Du sagst: 'Ich möchte ein Brot ___.'",opts:["bestellen","kochen","arbeiten","bezahlen"],ans:"bestellen",hint:"The verb for placing an order at a shop or restaurant."},
{type:"match",pairs:[{trg:"essen",src:"to eat"},{trg:"kaufen",src:"to buy"},{trg:"kochen",src:"to cook"},{trg:"arbeiten",src:"to work"}]}
]},

// ─── Lesson: Eigenschaften und mehr ───
{id:"deu_r2l7",title:"Eigenschaften und mehr",icon:"🎯",xp:15,board:true,steps:[
{type:"intro",title:"Eigenschaften und mehr",desc:"Known or unknown, clear or wrong: learn adjectives that describe things and situations. Plus everyday verbs like spielen, sitzen, and liegen.",goals:["Learn adjective pairs: fremd/bekannt, klar/gleich","Master position verbs: sitzen, liegen","Distinguish action verbs from state verbs"]},
{type:"mc",q:"Das Café ist ___. Alle Tische haben Leute.",opts:["besetzt","fremd","geschlossen","falsch"],ans:"besetzt",hint:"The cafe is not closed, it is full. Every table has people."},
{type:"teach",trg:"fremd",src:"foreign, strange, unfamiliar",pos:"adj",gender:null,note:"Adjective. Not negative, just unfamiliar.",example:"A: Ich bin fremd hier.\nB: Kein Problem, ich helfe dir!",exampleSrc:"A: I am a stranger here.\nB: No problem, I will help you!",funFact:"'Ich bin fremd hier' = I am a stranger here. Not negative. Just means unfamiliar with the place."},
{type:"teach",trg:"bekannt",src:"well-known, famous",pos:"adj",gender:null,note:"Adjective. Past participle of bekennen.",example:"A: Ist das Brandenburger Tor bekannt?\nB: Ja, es ist sehr bekannt!",exampleSrc:"A: Is the Brandenburg Gate well-known?\nB: Yes, it is very famous!",funFact:"'Das Brandenburger Tor ist bekannt.' The opposite of fremd in a way. Bekannt = known, fremd = unknown."},
{type:"teach",trg:"klar",src:"clear, obvious",pos:"adj",gender:null,note:"Adjective/adverb. 'Alles klar?' = All clear?",example:"A: Alles klar?\nB: Ja, alles klar!",exampleSrc:"A: Everything clear?\nB: Yes, all clear!",funFact:"'Alles klar?' = Everything clear? / All good? One of the most common German phrases. Use it constantly."},
{type:"teach",trg:"gleich",src:"same, equal; right away",pos:"adj",gender:null,note:"Two meanings! Context tells you which.",example:"A: Die Farben sind gleich.\nB: Ich komme gleich!",exampleSrc:"A: The colors are the same.\nB: I will be there right away!",funFact:"Two meanings! 'Das ist gleich' = that is the same. 'Ich komme gleich' = I am coming right away. Context decides."},
{type:"teach",trg:"spielen",src:"to play",pos:"verb",gender:null,note:"Regular verb. Spielplatz = playground.",example:"A: Spielst du gern?\nB: Ja, ich spiele sehr gern!",exampleSrc:"A: Do you like to play?\nB: Yes, I love to play!",funFact:"Spielplatz = playground. Spielen covers both playing games and playing music. 'Klavier spielen' = to play piano."},
{type:"verb_table",title:"spielen (to play)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"spiele",src:"I play"},{pronoun:"du",form:"spielst",src:"you play"},{pronoun:"er/sie/es",form:"spielt",src:"he/she/it plays"},{pronoun:"wir",form:"spielen",src:"we play"},{pronoun:"ihr",form:"spielt",src:"you all play"},{pronoun:"sie/Sie",form:"spielen",src:"they/you (formal) play"}]}],note:"Regular pattern. Fußball spielen = to play football."},
{type:"teach",trg:"sitzen",src:"to sit (state)",pos:"verb",gender:null,note:"State verb: already sitting. Setzen = to sit down (action).",example:"A: Wo sitzt du?\nB: Ich sitze im Café.",exampleSrc:"A: Where are you sitting?\nB: I am sitting in the cafe.",funFact:"Sitzen = you ARE sitting (state). Setzen = you SIT DOWN (action). German distinguishes between the motion and the result."},
{type:"teach",trg:"liegen",src:"to lie, to be located",pos:"verb",gender:null,note:"State verb. Legen = to lay/put (action).",example:"A: Wo liegt Berlin?\nB: Berlin liegt an der Spree.",exampleSrc:"A: Where is Berlin located?\nB: Berlin is on the Spree river.",funFact:"Liegen = it is lying there (state). Legen = you lay it down (action). 'Berlin liegt an der Spree' = Berlin is situated on the Spree."},
{type:"mc",q:"Die Tür ist ___. Wir können nicht hinein.",opts:["richtig","geschlossen","besetzt","groß"],ans:"geschlossen",hint:"The door is shut. We cannot go in."},
{type:"fb",s:"Ich möchte etwas {1}.",a:["bestellen"],opts:["bestellen","bezahlen","bleiben","bringen"],hint:"You want to order something at a restaurant.",sSrc:"I would like to order something."},
{type:"mc",q:"'Alles klar?' means:",opts:["Everything closed?","Everyone here?","Everything clear?","Everything false?"],ans:"Everything clear?",hint:"Break this greeting into its two short parts and translate each."},
{type:"match",pairs:[{trg:"essen",src:"to eat"},{trg:"kaufen",src:"to buy"},{trg:"arbeiten",src:"to work"},{trg:"kochen",src:"to cook"},{trg:"bezahlen",src:"to pay"}]},
{type:"fb",s:"Ist der Platz {1}?",a:["besetzt"],opts:["besetzt","geschlossen","bekannt","fremd"],hint:"You want to know if the seat is taken.",sSrc:"Is the seat taken?"},
{type:"tip",title:"Action vs State Verb Pairs",text:"German distinguishes between doing something and the result:\n\nlegen (to lay) vs liegen (it is lying)\nsetzen (to seat) vs sitzen (it is sitting)\nstellen (to place) vs stehen (it is standing)\n\nThe -e- verb is the ACTION. The -i- verb is the STATE.",deepDive:{title:"Upright vs flat, state vs action",text:"The key question is: is the object UPRIGHT (bottle, vase, lamp) or FLAT (book, paper, clothes)?\n\nUpright: stehen (state) / stellen (action)\nFlat: liegen (state) / legen (action)\n\nThen ask: LOCATION (already there) or ACTION (you move it)?\n\nLocation: stehen / liegen + dative (wo?)\nAction: stellen / legen + accusative (wohin?)\n\nExample: 'Das Buch liegt auf dem Tisch' (state, flat). 'Ich lege das Buch auf den Tisch' (action, flat)."}},
{type:"mc",q:"'Wo sitzt du?' means what in English?",opts:["Are you sitting down?","Why are you sitting?","Where are you going?","Where are you sitting?"],ans:"Where are you sitting?",hint:"Sitzen is the state verb meaning to be in a seated position."},

{"type":"fb","s":"Die Kinder {1} im Garten.","a":["spielen"],"opts":["spielen","lernen","schlafen","essen"],"hint":"An activity children do for fun outside.","sSrc":"The children play in the garden."}]},
// --- L6: Der Döner-Umweg (Story Climax) ---
{id:"deu_r2l8",title:"Der Döner-Umweg",icon:"\uD83C\uDF2F",xp:15,board:true,steps:[
{type:"intro",title:"Der Döner-Umweg",desc:"Verumius has been walking for an hour. He is hungry, lost, and his map is useless. Then he smells something incredible from a Döner stand by the Spree.",goals:["Learn travel and transport verbs","Navigate public transport in German","Discover Berlin's Döner culture"]},
{type:"teach",trg:"fahren",src:"to drive, to go by vehicle",pos:"verb",gender:null,note:"Irregular: ich fahre, du fährst, er fährt.",example:"A: Fährst du mit dem Bus?\nB: Nein, ich fahre mit der U-Bahn.",exampleSrc:"A: Are you going by bus?\nB: No, I am going by subway.",funFact:"The ä in fährst/fährt is a stem vowel change. Many common German verbs do this: schlafen to schläft, laufen to läuft."},
{type:"verb_table",title:"fahren (to travel/drive) - present tense",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"fahre",src:"I drive/travel"},{pronoun:"du",form:"fährst",src:"you drive/travel"},{pronoun:"er/sie/es",form:"fährt",src:"he/she/it drives/travels"}]},{label:"Plural",rows:[{pronoun:"wir",form:"fahren",src:"we drive/travel"},{pronoun:"ihr",form:"fahrt",src:"you all drive/travel"},{pronoun:"sie/Sie",form:"fahren",src:"they/you (formal) drive/travel"}]}],note:"Vowel change a to ä in du and er/sie/es forms. Common with all transport verbs."},
{type:"teach",trg:"nehmen",src:"to take",pos:"verb",gender:null,note:"Irregular: ich nehme, du nimmst, er nimmt.",example:"A: Welchen Zug nimmst du?\nB: Ich nehme den ICE nach Hamburg.",exampleSrc:"A: Which train are you taking?\nB: I am taking the ICE to Hamburg.",funFact:"Irregular: the e becomes i in du/er forms. 'Ich nehme den Bus' = I will take the bus. Essential for transit."},
{type:"verb_table",title:"nehmen (to take)",groups:[{label:"Present tense (stem change: e → i + consonant change)",rows:[{pronoun:"ich",form:"nehme",src:"I take"},{pronoun:"du",form:"nimmst",src:"you take"},{pronoun:"er/sie/es",form:"nimmt",src:"he/she/it takes"},{pronoun:"wir",form:"nehmen",src:"we take"},{pronoun:"ihr",form:"nehmt",src:"you all take"},{pronoun:"sie/Sie",form:"nehmen",src:"they/you (formal) take"}]}],note:"Double change: e → i AND h → mm. One of German's most irregular common verbs."},
{type:"teach",trg:"laufen",src:"to walk, to run",pos:"verb",gender:null,note:"Irregular: ich laufe, du läufst, er läuft.",example:"A: Laufen wir?\nB: Ja, der Bahnhof ist nicht weit.",exampleSrc:"A: Shall we walk?\nB: Yes, the station is not far.",funFact:"In northern Germany, laufen = to walk. In southern Germany, laufen = to run. Geography changes meaning!"},
{type:"verb_table",title:"laufen (to walk/run)",groups:[{label:"Present tense (stem change: au → äu)",rows:[{pronoun:"ich",form:"laufe",src:"I walk/run"},{pronoun:"du",form:"läufst",src:"you walk/run"},{pronoun:"er/sie/es",form:"läuft",src:"he/she/it walks/runs"},{pronoun:"wir",form:"laufen",src:"we walk/run"},{pronoun:"ihr",form:"lauft",src:"you all walk/run"},{pronoun:"sie/Sie",form:"laufen",src:"they/you (formal) walk/run"}]}],note:"au → äu in du/er forms. Northern Germany: walk. Southern Germany: run."},
{type:"teach",trg:"einsteigen",src:"to get in, to board",pos:"verb",gender:null,note:"Separable: Steigen Sie ein!",example:"A: Bitte einsteigen!\nB: Danke, ich steige ein.",exampleSrc:"A: Please board!\nB: Thanks, I am boarding.",funFact:"Separable: 'Steigen Sie ein!' = Board! Ein = in. You hear this on every platform: 'Bitte einsteigen, die Türen schließen!'"},
{type:"teach",trg:"aussteigen",src:"to get out, to exit",pos:"verb",gender:null,note:"Separable: Bitte aussteigen!",example:"A: Wir müssen hier aussteigen.\nB: Okay, ich steige aus.",exampleSrc:"A: We have to get out here.\nB: Okay, I am getting out.",funFact:"'Bitte aussteigen!' = Please exit! You hear this on every U-Bahn. Aus = out. Ein and aus are opposite prefixes."},
{type:"teach",trg:"umsteigen",src:"to transfer, to change trains",pos:"verb",gender:null,note:"Separable: Sie müssen umsteigen.",example:"A: Muss ich umsteigen?\nB: Ja, am Alexanderplatz.",exampleSrc:"A: Do I need to transfer?\nB: Yes, at Alexanderplatz.",funFact:"Um = around/change. 'Sie müssen am Alexanderplatz umsteigen' = You have to transfer at Alexanderplatz. A daily Berlin experience."},
{type:"teach",trg:"der Spaß",src:"fun",pos:"noun",gender:"m",note:"Masculine noun. 'Das macht Spaß!' = That is fun!",example:"A: Macht Berlin Spaß?\nB: Ja, Berlin macht viel Spaß!",exampleSrc:"A: Is Berlin fun?\nB: Yes, Berlin is a lot of fun!",funFact:"'Das macht Spaß!' = That is fun! (literally 'That makes fun'). 'Viel Spaß!' = Have fun! Germans use 'machen' (to make) with fun, not 'haben' (to have)."},
{type:"teach",trg:"das Stück",src:"piece, item",pos:"noun",gender:"n",note:"Neuter noun. 'Ein Stück Kuchen' = a piece of cake.",example:"A: Ein Stück, bitte!\nB: Hier, ein Stück Döner.",exampleSrc:"A: One piece, please!\nB: Here, one piece of Döner.",funFact:"'Ein Stück' is how you order at counters. 'Zwei Stück' for two pieces. At a bakery: 'Drei Stück Brötchen, bitte.'"},
{type:"fb",s:"Bitte {1}! Der Zug fährt ab.",a:["einsteigen"],opts:["einsteigen","aussteigen","umsteigen","bleiben"],hint:"The train is leaving. You need to board now.",sSrc:"Please board! The train is departing."}
,
{"type":"mc","q":"Was bedeutet 'der Spaß'?","opts":["fun","stress","work","sleep"],"ans":"fun","hint":"What you have when you enjoy yourself."}]},
{id:"deu_r2l8b",title:"Der Döner-Umweg (Teil 2)",icon:"\uD83C\uDF2F",xp:15,board:true,steps:[
{type:"intro",title:"Der Döner-Umweg (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"bekommen",src:"to get, to receive",pos:"verb",gender:null,note:"FALSE FRIEND! Not 'to become'!",example:"A: Ich bekomme einen Döner.\nB: Mit alles?",exampleSrc:"A: I am getting a Döner.\nB: With everything?",funFact:"FAMOUS FALSE FRIEND! 'Bekommen' does NOT mean 'to become.' 'Ich bekomme einen Döner' = I am GETTING a Döner, NOT 'I am becoming a Döner.'"},
{type:"teach",trg:"der Fluss",src:"the river",pos:"noun",gender:"m",note:"Masculine noun. Berlin's river: die Spree.",example:"A: Ist das ein Fluss?\nB: Ja, das ist die Spree.",exampleSrc:"A: Is that a river?\nB: Yes, that is the Spree.",funFact:"Berlin's river is die Spree, but Fluss itself is masculine (der Fluss). The Spree flows through the heart of Berlin."},
{type:"teach",trg:"die Sonne",src:"the sun",pos:"noun",gender:"f",note:"Feminine noun. 'Sonnenschein' = sunshine.",example:"A: Die Sonne scheint!\nB: Ja, endlich Sonne in Berlin!",exampleSrc:"A: The sun is shining!\nB: Yes, finally sun in Berlin!",funFact:"'Sonnenschein' = sunshine. Germans celebrate sun like it is a miracle. In Berlin, where grey skies dominate, a sunny day changes the whole city's mood."},
{type:"teach",trg:"der See",src:"the lake",pos:"noun",gender:"m",note:"Masculine noun. But die See = the sea!",example:"A: Gehen wir zum See?\nB: Ja, der See ist schön.",exampleSrc:"A: Shall we go to the lake?\nB: Yes, the lake is beautiful.",funFact:"GENDER TRAP! der See = the lake. die See = the sea. Same word, different gender, different meaning! Berlin has many lakes (Seen) for summer swimming."},
{type:"mc",q:"'Ich bekomme einen Kaffee' means:",opts:["I am getting a coffee","I am becoming a coffee","I am buying a coffee","I am making a coffee"],ans:"I am getting a coffee",hint:"Bekommen is a famous false friend. It means 'to receive/get,' not 'to become.'"},
{type:"mc",q:"'der See' means ___, but 'die See' means ___.",opts:["the sea / the lake","the lake / the sea","the river / the lake","the lake / the river"],ans:"the lake / the sea",hint:"Same word, different gender = completely different meaning."},
{type:"fb",s:"Ich möchte {1}, bitte. Ein Stück.",a:["bestellen"],opts:["bestellen","bezahlen","bekommen","bleiben"],hint:"You want to place an order.",sSrc:"I would like to order, please. One piece."},
{type:"mc",q:"You need to change trains. The announcement says:",opts:["Bitte einsteigen!","Bitte aussteigen!","Bitte umsteigen!","Bitte aufstehen!"],ans:"Bitte umsteigen!",hint:"'Um' means change/around. Which verb means to transfer?"},
{type:"fb",s:"Können Sie mir die {1} zum Bahnhof zeigen?",a:["Richtung"],opts:["Richtung","Kreuzung","Haltestelle","Ecke"],hint:"You are asking someone to show you the direction to the station.",sSrc:"Can you show me the direction to the train station?"},
{type:"tip",title:"Döner Culture",text:"Germany eats about 720 million Döner Kebabs per year.\nBerlin alone has over 1,600 Döner shops.\nThe German Döner was invented in Berlin in the 1970s by Turkish immigrants.\nIt is now Germany's most popular fast food, ahead of burgers and pizza."},
{type:"mc",q:"Was bedeutet 'der Fluss'?",opts:["to walk, to run","to get in, to board","to take","the river"],ans:"the river",hint:"A flowing body of water. Related to 'fließen' (to flow). The Spree is one in Berlin."},
{type:"fb",s:"{1} scheint!",a:["die Sonne"],opts:["einsteigen","laufen","die Sonne","aussteigen"],hint:"The bright star in our sky. Feminine noun: remember the article!",sSrc:"The sun is shining!"}
]},
// --- L7: Alles zusammen! (Quiz) ---
{id:"deu_r2l9",title:"Alles zusammen!",icon:"\uD83C\uDFC6",xp:20,board:true,steps:[
{type:"intro",title:"Alles zusammen!",desc:"Time to test everything: directions, articles, places, adjectives, and verbs. Show what you have learned in Unit 2!",goals:["Test all Unit 2 vocabulary","Demonstrate article mastery","Apply direction and place knowledge"]},
{type:"teach",trg:"abfahren",src:"to depart (vehicle)",pos:"verb",gender:null,note:"Separable: Der Zug fährt um 10 Uhr ab.",example:"A: Wann fährt der Zug ab?\nB: Der Zug fährt um zehn ab.",exampleSrc:"A: When does the train depart?\nB: The train departs at ten.",funFact:"Separable: 'Der Zug fährt um 10 Uhr ab.' Ab = away/off. The 'ab' flies to the end of the sentence."},
{type:"teach",trg:"ankommen",src:"to arrive",pos:"verb",gender:null,note:"Separable: Wann kommen Sie an?",example:"A: Wann kommst du an?\nB: Ich komme um drei an.",exampleSrc:"A: When do you arrive?\nB: I arrive at three.",funFact:"Separable: 'Wann kommen Sie an?' = When do you arrive? An = at. Arrival is literally 'coming at' a place."},
{type:"teach",trg:"besuchen",src:"to visit",pos:"verb",gender:null,note:"Inseparable prefix verb. Be- verbs never separate.",example:"A: Ich besuche das Museum.\nB: Welches Museum?",exampleSrc:"A: I am visiting the museum.\nB: Which museum?",funFact:"Inseparable: be- prefix verbs NEVER separate. 'Ich besuche' stays together. For sightseeing, use besichtigen. For people, use besuchen."},
{type:"teach",trg:"fliegen",src:"to fly",pos:"verb",gender:null,note:"Irregular. Past: flog.",example:"A: Fliegst du nach Berlin?\nB: Ja, ich fliege morgen.",exampleSrc:"A: Are you flying to Berlin?\nB: Yes, I am flying tomorrow.",funFact:"Fliegen, Flug, Flughafen, Flugzeug: the Flug- family covers everything airborne. All from the same root meaning 'to fly.'"},
{type:"teach",trg:"gefallen",src:"to please, to like",pos:"verb",gender:null,note:"The thing you like is the SUBJECT. Dative construction.",example:"A: Berlin gefällt mir!\nB: Mir auch!",exampleSrc:"A: I like Berlin! (Berlin pleases me!)\nB: Me too!",funFact:"'Berlin gefällt mir!' = Berlin pleases me! = I like Berlin. The thing you like is the SUBJECT. This is backwards from English."},
{type:"match",pairs:[{trg:"ankommen",src:"to arrive"},{trg:"besuchen",src:"to visit"},{trg:"fliegen",src:"to fly"},{trg:"gefallen",src:"to please, to like"}]},
{type:"teach",trg:"schließen",src:"to close",pos:"verb",gender:null,note:"Irregular. Past participle: geschlossen.",example:"A: Das Museum schließt um 18 Uhr.\nB: Dann müssen wir uns beeilen!",exampleSrc:"A: The museum closes at 6 PM.\nB: Then we need to hurry!",funFact:"Formal version of 'zumachen.' 'Das Museum schließt' = the museum closes. 'Geschlossen' = closed (adjective)."},
{type:"mc",q:"Das Museum ___ um 18 Uhr.",opts:["schließt","gefällt","fliegt","besucht"],ans:"schließt",hint:"At 6 PM the museum stops being open."},
{type:"teach",trg:"gern(e)",src:"gladly, with pleasure",pos:"adv",gender:null,note:"Added after a verb to mean 'like doing.'",example:"A: Ich laufe gern.\nB: Ich auch! Berlin ist toll zum Laufen.",exampleSrc:"A: I like walking.\nB: Me too! Berlin is great for walking.",funFact:"Verb + gern = enjoy doing. 'Ich laufe gern' = I like to walk. 'Ich koche gern' = I like to cook. Simple and powerful."},
{type:"teach",trg:"leider",src:"unfortunately",pos:"adv",gender:null,note:"Adverb. Used constantly in German.",example:"A: Kommst du mit?\nB: Leider nein, ich muss arbeiten.",exampleSrc:"A: Are you coming along?\nB: Unfortunately no, I have to work.",funFact:"'Leider nein' = Unfortunately no. Germans use this constantly. It softens a rejection without being rude."},
{type:"teach",trg:"trinken",src:"to drink",pos:"verb",gender:null,note:"Irregular past (trank), but regular present.",example:"A: Was möchten Sie trinken?\nB: Einen Kaffee, bitte.",exampleSrc:"A: What would you like to drink?\nB: A coffee, please.",funFact:"'Trinkgeld' = tip (literally 'drink money'). In Germany, tips are usually 5-10% of the bill, rounded up."},
{type:"verb_table",title:"trinken (to drink)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"trinke",src:"I drink"},{pronoun:"du",form:"trinkst",src:"you drink"},{pronoun:"er/sie/es",form:"trinkt",src:"he/she/it drinks"},{pronoun:"wir",form:"trinken",src:"we drink"},{pronoun:"ihr",form:"trinkt",src:"you all drink"},{pronoun:"sie/Sie",form:"trinken",src:"they/you (formal) drink"}]}],note:"Regular in present tense. Was trinken Sie? = What are you drinking?"},
{type:"mc",q:"Wie komme ich zum Bahnhof? ___ und dann ___.",opts:["Rechts ... Süden","Geradeaus ... links","Norden ... rechts","Links ... geradeaus"],ans:"Geradeaus ... links",hint:"The most common direction pattern: straight ahead, then turn."},
{type:"mc",q:"Das ist ___ Kirche.",opts:["einer","eines","eine","ein"],ans:"eine",hint:"Kirche is feminine (die Kirche). What is the feminine indefinite article?"},
{type:"fb",s:"{1} Museum ist sehr bekannt.",a:["Das"],opts:["Das","Der","Die","Ein"],hint:"Museum is neuter. Which definite article?",sSrc:"The museum is very well-known."},
{type:"mc",q:"Die Straße ist ___. (long)",opts:["langer","langes","lange","lang"],ans:"lang",hint:"After 'ist,' adjectives have NO ending. Base form only."},
{type:"mc",q:"In 'Der Mann sucht den Bahnhof,' who is performing the action?",opts:["The man","The article","The station","The verb"],ans:"The man",hint:"The subject DOES the action. Which case is nominative here?"},
{type:"match",pairs:[{trg:"geradeaus",src:"straight ahead"},{trg:"die Kreuzung",src:"intersection"},{trg:"umsteigen",src:"to transfer"},{trg:"geschlossen",src:"closed"},{trg:"ankommen",src:"to arrive"},{trg:"leider",src:"unfortunately"}]},
{type:"mc",q:"'Berlin gefällt mir' means:",opts:["Berlin is gone","I like Berlin","Berlin falls down","I feel Berlin"],ans:"I like Berlin",hint:"Gefallen = to please. The subject does the pleasing, not the experiencing."},
{type:"fb",s:"Ich fliege {1} Berlin.",a:["nach"],opts:["nach","zu dunkel","bei","an"],hint:"For traveling TO cities and countries, which preposition do you use?",sSrc:"I am flying to Berlin."},
{type:"teach",trg:"brauchen",src:"to need",pos:"verb",gender:null,note:"Regular verb. Ich brauche, du brauchst, er braucht.",example:"A: Was brauchst du?\nB: Ich brauche eine Karte von Berlin.",exampleSrc:"A: What do you need?\nB: I need a map of Berlin.",funFact:"In spoken German, brauchen sometimes replaces müssen with nicht: Du brauchst nicht kommen = you don't need to come."},
{type:"drag_fill",s:"Entschuldigung, {1} ist {2} Apotheke? Ich {3} Medizin.",blanks:{"1":"wo","2":"die","3":"brauche"},pool:["wo","die","brauche","wohin","der","kaufe"],hint:"Where (location) is the (feminine) pharmacy? I need medicine.",sSrc:"Excuse me, where is the pharmacy? I need medicine."},
{type:"mc",q:"Which compound noun is NEUTER?",opts:["der Parkplatz","die Innenstadt","das Rathaus","der Stadtplan"],ans:"das Rathaus",hint:"Compound nouns take the gender of the LAST word."}
,
{"type":"fb","s":"Ich trinke {1} Kaffee.","a":["gern"],"opts":["gern","nie","schlecht","viel"],"hint":"Expresses that you enjoy doing something.","sSrc":"I like drinking coffee."}]},
// --- L8: Morgen versuche ich es nochmal (Resolution) ---
{id:"deu_r2l10",title:"Morgen versuche ich es nochmal",icon:"\uD83C\uDF07",xp:15,board:true,steps:[
{type:"intro",title:"Morgen versuche ich es nochmal",desc:"Day 1 in Berlin is ending. The Bürgeramt? Not found. But Verumius discovered something better: the art of being lost in Berlin.",goals:["Learn sondern vs aber","Master denn as conjunction","Reflect on Unit 2 vocabulary"]},
{type:"teach",trg:"sondern",src:"but rather (after negation)",pos:"conj",gender:null,note:"ONLY follows nicht/kein. Corrects a negative.",example:"A: Das ist nicht die Bank.\nB: Nein, sondern die Apotheke!",exampleSrc:"A: That is not the bank.\nB: No, but rather the pharmacy!",funFact:"'Nicht das Bürgeramt, sondern der Döner-Stand.' Sondern ONLY follows a negation. Aber = but (general). Sondern = but RATHER (correcting)."},
{type:"teach",trg:"die Idee",src:"the idea",pos:"noun",gender:"f",note:"Feminine noun. From Greek via French.",example:"A: Ich habe eine Idee!\nB: Was für eine Idee?",exampleSrc:"A: I have an idea!\nB: What kind of idea?",funFact:"Same root as English 'idea.' German borrowed it from Greek via French. Die Idee is always feminine."},
{type:"teach",trg:"die Sache",src:"the thing, matter",pos:"noun",gender:"f",note:"Feminine noun. More formal than 'Ding.'",example:"A: Das ist meine Sache.\nB: Okay, ich frage nicht mehr.",exampleSrc:"A: That is my business.\nB: Okay, I will not ask again.",funFact:"'Das ist meine Sache' = That is my business/matter. More formal than 'Ding' (thing). 'Tatsache' = fact (literally 'deed-thing')."},
{type:"tip",title:"Aber vs Sondern",text:"Aber = but (general contrast):\nDas Hotel ist klein, aber schön.\n\nSondern = but rather (corrects a negation):\nDas ist nicht die Bank, sondern die Apotheke.\n\nRule: If there is 'nicht' or 'kein' before 'but,' use sondern.\nOtherwise, use aber."},
{type:"mc",q:"Das ist nicht die Bank, ___ die Apotheke.",opts:["sondern","aber","denn","und"],ans:"sondern",hint:"After a negation (nicht), which 'but' corrects the statement?"},
{type:"tip",title:"Denn: Two Lives",text:"Particle in questions: 'Was ist denn das?' (adds curiosity)\n\nConjunction meaning 'because/for':\n'Ich gehe ins Café, denn ich bin müde.'\n\nYou learned the particle earlier. Now you know the conjunction too."},
{type:"mc",q:"Ich gehe zum Bahnhof, ___ ich fahre nach München.",opts:["aber","denn","dann","sondern"],ans:"denn",hint:"You are giving the REASON (because) you are going to the station."},
{type:"fb",s:"Das Museum ist nicht klein, {1} groß.",a:["sondern"],opts:["sondern","aber","denn","und"],hint:"After 'nicht' plus correcting = which conjunction?",sSrc:"The museum is not small, but rather big."},
{type:"tip",title:"Berlin Survival Guide",text:"What Verumius learned today:\n\nKönnen Sie mir helfen? = Can you help me?\nEntschuldigung, wo ist...? = Excuse me, where is...?\nGeradeaus, dann links/rechts = Straight, then left/right\nNEVER cross on red (social death)\n'Mit alles?' at the Döner stand = With everything?\nDöner is always a good decision."},
{type:"mc",q:"'Berlin gefällt mir' uses which pattern?",opts:["Berlin is the object","The person who likes is the subject","The thing you like is the subject","Gefallen needs accusative"],ans:"The thing you like is the subject",hint:"In this verb pattern, the city does the action of pleasing. Which grammatical role does that make it?"},
{type:"match",pairs:[{trg:"sondern",src:"but rather (after negation)"},{trg:"denn",src:"because, for"},{trg:"die Idee",src:"idea"},{trg:"die Sache",src:"thing, matter"},{trg:"gefallen",src:"to please, to like"}]},
{type:"tip",title:"Gender Cheat Sheet: Unit 2",text:"-ung = die (Richtung, Kreuzung, Verbindung, Öffnungszeit)\n-ei = die (Bäckerei)\n-e = usually die (Straße, Brücke, Kirche, Ecke, Sonne)\n-chen = das (coming in Unit 3!)\nCompound nouns = gender of LAST word\nLatin/Greek loans = often das (Hotel, Café, Museum, Kino)\nder See = lake, die See = sea (the ultimate trap)"},
{type:"fb",s:"Berlin {1} mir!",a:["gefällt"],opts:["gefällt","gefallt","gefalle","gefällst"],hint:"Berlin is singular (it). What ending does gefallen get for er/sie/es?",sSrc:"Berlin pleases me!"},
{type:"mc",q:"'Ich trinke nicht Tee, ___ Kaffee.' Which conjunction fits the blank?",opts:["aber","denn","oder","sondern"],ans:"sondern",hint:"This conjunction corrects a negation. It always follows nicht or kein."}]}

,

{id:"deu_r2l11",title:"Kleine Wörter, große Wirkung",icon:"💡",xp:15,board:true,steps:[
{type:"intro",title:"Kleine Wörter, große Wirkung",desc:"Small words with big impact! Learn essential adverbs, connectors, and prepositions that glue German sentences together.",goals:["Learn 20 essential adverbs, prepositions, and connectors","Use time words like jetzt, bald, schon in sentences","Navigate conversations with auf, durch, über, vor"]},
{type:"teach",trg:"bald",src:"soon",pos:"adv",gender:null,note:"Adverb of time. Very common in everyday speech.",example:"A: Wann kommt der Bus?\nB: Er kommt bald.",exampleSrc:"A: When does the bus come?\nB: It comes soon.",funFact:"Germans say 'Bis bald!' (See you soon!) as a casual goodbye."},
{type:"teach",trg:"dann",src:"then",pos:"adv",gender:null,note:"Adverb. Used to sequence events or actions.",example:"A: Zuerst gehen wir ins Museum.\nB: Und dann?\nA: Dann essen wir Pizza.",exampleSrc:"A: First we go to the museum.\nB: And then?\nA: Then we eat pizza.",funFact:"Dann is one of the top 50 most frequent German words."},
{type:"teach",trg:"immer",src:"always",pos:"adv",gender:null,note:"Adverb of frequency. Opposite: nie (never).",example:"A: Fährst du immer mit dem Bus?\nB: Ja, ich fahre immer mit dem Bus.",exampleSrc:"A: Do you always take the bus?\nB: Yes, I always take the bus.",funFact:"'Immer geradeaus' (always straight ahead) is the most common direction you will hear in Germany."},
{type:"teach",trg:"jetzt",src:"now",pos:"adv",gender:null,note:"Adverb of time. Emphasizes the present moment.",example:"A: Wann gehen wir?\nB: Jetzt! Komm!",exampleSrc:"A: When do we go?\nB: Now! Come!",funFact:"In southern Germany and Austria, people often say 'jetzt' as 'jetz' or even 'etz'."},
{type:"teach",trg:"nie",src:"never",pos:"adv",gender:null,note:"Adverb of frequency. Opposite: immer (always).",example:"A: Fährst du mit dem Taxi?\nB: Nein, ich fahre nie mit dem Taxi.",exampleSrc:"A: Do you take the taxi?\nB: No, I never take the taxi.",funFact:"The phrase 'nie wieder' (never again) is used for strong emphasis."},
{type:"mc",q:"Ich fahre ___ mit dem Taxi. Es ist zu teuer.",opts:["nie","bald","jetzt","immer"],ans:"nie",hint:"You absolutely refuse to take taxis because of the cost."},
{type:"teach",trg:"noch",src:"still, yet",pos:"adv",gender:null,note:"Adverb. Context changes meaning: noch = still, noch nicht = not yet.",example:"A: Bist du noch im Hotel?\nB: Ja, ich bin noch hier.",exampleSrc:"A: Are you still at the hotel?\nB: Yes, I am still here.",funFact:"'Noch ein Bier, bitte!' (Another beer, please!) is a survival phrase in Germany."},
{type:"teach",trg:"nur",src:"only",pos:"adv",gender:null,note:"Adverb. Limits or restricts what follows.",example:"A: Wie viel kostet das?\nB: Nur zwei Euro.",exampleSrc:"A: How much does that cost?\nB: Only two euros.",funFact:"Nur is related to English 'narrow'. Both come from the idea of restriction."},
{type:"teach",trg:"oft",src:"often",pos:"adv",gender:null,note:"Adverb of frequency. Between immer and manchmal.",example:"A: Gehst du oft ins Kino?\nB: Ja, ich gehe oft ins Kino.",exampleSrc:"A: Do you go to the cinema often?\nB: Yes, I go to the cinema often.",funFact:"The comparative form is 'öfter' (more often), with an umlaut."},
{type:"teach",trg:"schon",src:"already",pos:"adv",gender:null,note:"Adverb. Can also express surprise or reassurance.",example:"A: Ist der Zug schon da?\nB: Ja, er ist schon am Gleis.",exampleSrc:"A: Is the train already there?\nB: Yes, it is already at the platform.",funFact:"'Schon gut' means 'it is alright' and is used to reassure someone."},
{type:"teach",trg:"sofort",src:"immediately",pos:"adv",gender:null,note:"Adverb. Stronger than 'bald' (soon).",example:"A: Wann kann ich das Zimmer haben?\nB: Sofort! Es ist fertig.",exampleSrc:"A: When can I have the room?\nB: Immediately! It is ready.",funFact:"German bureaucrats love this word. 'Sofortige Maßnahmen' means immediate measures."},
{type:"fb",s:"Das kostet {1} zwei Euro. Es ist billig!",a:["nur"],opts:["nur","nie","oft","schon"],hint:"This adverb means 'only' and limits the amount.",sSrc:"That costs only two euros. It is cheap!"}
,
{"type":"mc","q":"Was bedeutet 'dann'?","opts":["then","now","never","here"],"ans":"then","hint":"A word for what comes next in time."},
{"type":"mc","q":"Was bedeutet 'sofort'?","opts":["immediately","slowly","later","sometimes"],"ans":"immediately","hint":"Without any delay at all."}]},
{id:"deu_r2l11b",title:"Kleine Wörter, große Wirkung (Teil 2)",icon:"💡",xp:15,board:true,steps:[
{type:"intro",title:"Kleine Wörter, große Wirkung (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"vielleicht",src:"perhaps, maybe",pos:"adv",gender:null,note:"Adverb. Softens statements and suggestions.",example:"A: Gehen wir ins Museum?\nB: Ja, vielleicht am Nachmittag.",exampleSrc:"A: Shall we go to the museum?\nB: Yes, perhaps in the afternoon.",funFact:"Vielleicht literally breaks down to 'viel' (much) + 'leicht' (easy/light), meaning 'easily possible'."},
{type:"teach",trg:"wieder",src:"again",pos:"adv",gender:null,note:"Adverb. Indicates repetition.",example:"A: Der Bus ist weg!\nB: Kein Problem. Er kommt wieder.",exampleSrc:"A: The bus is gone!\nB: No problem. It comes again.",funFact:"'Auf Wiedersehen' literally means 'until seeing again'. It is the formal goodbye."},
{type:"teach",trg:"an",src:"on, at (a surface or location)",pos:"prep",gender:null,note:"Preposition. Used for surfaces and specific locations.",example:"A: Wo ist die Karte?\nB: Sie ist an der Wand.",exampleSrc:"A: Where is the map?\nB: It is on the wall.",funFact:"An der Haltestelle (at the bus stop) is one of the most common uses of 'an'."},
{type:"teach",trg:"auf",src:"on, upon, on top of",pos:"prep",gender:null,note:"Preposition. Used for horizontal surfaces.",example:"A: Wo ist mein Handy?\nB: Es ist auf dem Tisch.",exampleSrc:"A: Where is my phone?\nB: It is on the table.",funFact:"'Auf Deutsch' means 'in German'. You use 'auf' for languages."},
{type:"teach",trg:"durch",src:"through",pos:"prep",gender:null,note:"Preposition. Always takes accusative case.",example:"A: Wie komme ich zum Park?\nB: Gehen Sie durch die Straße.",exampleSrc:"A: How do I get to the park?\nB: Go through the street.",funFact:"A 'Durchgang' (throughway) combines durch + Gang (walk). Very logical!"},
{type:"fb",s:"Gehen Sie {1} die Straße bis zur Kirche.",a:["durch"],opts:["durch","auf","an","ab"],hint:"You need to go THROUGH the street to reach the church.",sSrc:"Go through the street to the church."},
{type:"teach",trg:"gegen",src:"against, around (time)",pos:"prep",gender:null,note:"Preposition. Also used for approximate times: gegen 8 Uhr.",example:"A: Wann kommst du?\nB: Gegen drei Uhr.",exampleSrc:"A: When are you coming?\nB: Around three o'clock.",funFact:"'Dagegen' (against it) is a common compound. Germans love stacking prepositions onto words."},
{type:"teach",trg:"über",src:"over, about, across",pos:"prep",gender:null,note:"Preposition. 'Über' also means 'about' a topic.",example:"A: Wie komme ich zum Museum?\nB: Gehen Sie über die Brücke.",exampleSrc:"A: How do I get to the museum?\nB: Go over the bridge.",funFact:"The English word 'uber' (as in uber-cool) comes directly from German über."},
{type:"teach",trg:"vor",src:"before, in front of",pos:"prep",gender:null,note:"Preposition. Time: vor einer Stunde (an hour ago). Place: vor dem Haus.",example:"A: Wo treffen wir uns?\nB: Vor dem Bahnhof.",exampleSrc:"A: Where do we meet?\nB: In front of the train station.",funFact:"'Vorgestern' means 'the day before yesterday'. Vor + gestern = before yesterday."},
{type:"teach",trg:"ab",src:"from (a point in time or place)",pos:"prep",gender:null,note:"Preposition. Marks a starting point: ab Montag (from Monday).",example:"A: Ab wann ist das Museum offen?\nB: Ab neun Uhr.",exampleSrc:"A: From when is the museum open?\nB: From nine o'clock.",funFact:"At airports, 'Abflug' (departure) uses 'ab' (away) + 'Flug' (flight)."},
{type:"fb",s:"Wir treffen uns {1} dem Bahnhof.",a:["vor"],opts:["vor","über","durch","ab"],hint:"Which preposition means 'in front of'?",sSrc:"We are meeting in front of the train station."},
{type:"teach",trg:"breit",src:"wide, broad",pos:"adj",gender:null,note:"Adjective. Opposite: schmal (narrow).",example:"A: Ist die Straße breit?\nB: Ja, sie ist sehr breit.",exampleSrc:"A: Is the street wide?\nB: Yes, it is very wide.",funFact:"The Kurfürstendamm in Berlin is one of the broadest avenues in Europe."},
{type:"mc",q:"What does 'vielleicht' mean?",opts:["perhaps","always","never","soon (formal)"],ans:"perhaps",hint:"Think of a word that expresses uncertainty."},
{type:"fb",s:"Der Zug kommt {1}. Wir müssen warten.",a:["bald"],opts:["bald","nie","schon","wieder"],hint:"The train is arriving in the near future.",sSrc:"The train comes soon. We have to wait."},
{type:"mc",q:"'Gehen Sie über die Brücke.' What does 'über' mean here?",opts:["behind","over","under","next to"],ans:"over",hint:"You cross something from one side to the other."},
{type:"match",pairs:[{trg:"jetzt",src:"now"},{trg:"immer",src:"always"},{trg:"oft",src:"often"},{trg:"nie",src:"never"},{trg:"noch",src:"still"}]},
{type:"mc",q:"Was bedeutet 'an'?",opts:["again","now","on, at (a surface or location)","often"],ans:"on, at (a surface or location)",hint:"A two-way preposition for touching contact points: 'an der Wand' (on the wall)."},
{type:"fb",s:"{1} drei Uhr.",a:["gegen"],opts:["gegen","über","oft","jetzt"],hint:"This preposition means 'around' or 'approximately' when used with times.",sSrc:"Around three o'clock."},
{type:"mc",q:"Was bedeutet 'breit'?",opts:["through","already","soon","wide, broad"],ans:"wide, broad",hint:"An adjective describing horizontal size. It describes a road or river, not its length."}
]},

{id:"deu_r2l12",title:"Wo ist das?",icon:"📍",xp:15,board:true,steps:[
{type:"intro",title:"Wo ist das?",desc:"Verumius needs to find his way around Berlin. Learn the names of places you will encounter in any German city.",goals:["Learn 18 city places and location nouns","Ask and answer 'Where is...?' questions","Navigate with confidence using place vocabulary"]},
{type:"teach",trg:"die Bäckerei",src:"the bakery",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Bäckereien.",example:"A: Wo ist die Bäckerei?\nB: Die Bäckerei ist um die Ecke.",exampleSrc:"A: Where is the bakery?\nB: The bakery is around the corner.",funFact:"Germany has over 10,000 bakeries. Fresh Brötchen (rolls) every morning is a national tradition."},
{type:"teach",trg:"der Bahnsteig",src:"the platform",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Bahnsteige. Bahn (railway) + Steig (path).",example:"A: Von welchem Bahnsteig fährt der Zug?\nB: Von Bahnsteig drei.",exampleSrc:"A: From which platform does the train leave?\nB: From platform three.",funFact:"German train stations announce 'Vorsicht am Bahnsteig!' (Caution at the platform!) before every train."},
{type:"teach",trg:"der Ausgang",src:"the exit",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Ausgänge. Aus (out) + Gang (way).",example:"A: Wo ist der Ausgang?\nB: Der Ausgang ist dort links.",exampleSrc:"A: Where is the exit?\nB: The exit is there on the left.",funFact:"Green 'Ausgang' signs are everywhere in Germany. They follow strict EU safety rules."},
{type:"teach",trg:"der Eingang",src:"the entrance",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Eingänge. Ein (in) + Gang (way).",example:"A: Ist das der Eingang?\nB: Nein, der Eingang ist auf der anderen Seite.",exampleSrc:"A: Is that the entrance?\nB: No, the entrance is on the other side.",funFact:"Eingang and Ausgang are perfect opposites: Ein (in) vs. Aus (out) + Gang (way)."},
{type:"teach",trg:"das Geschäft",src:"the shop, the business",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Geschäfte.",example:"A: Ist das Geschäft noch offen?\nB: Ja, bis acht Uhr.",exampleSrc:"A: Is the shop still open?\nB: Yes, until eight o'clock.",funFact:"On Sundays, almost all Geschäfte in Germany are closed. It is the law!"},
{type:"match",pairs:[{trg:"der Bahnsteig",src:"the platform"},{trg:"der Ausgang",src:"the exit"},{trg:"der Eingang",src:"the entrance"},{trg:"das Geschäft",src:"the shop, the business"}]},
{type:"teach",trg:"die Haltestelle",src:"the stop, the station",pos:"noun",gender:"f",note:"COMPOUND: Halte (stop) + Stelle (place).\nFeminine noun. Plural: die Haltestellen. Halte (hold/stop) + Stelle (place).",example:"A: Wo ist die Haltestelle?\nB: Die Haltestelle ist vor dem Hotel.",exampleSrc:"A: Where is the bus stop?\nB: The bus stop is in front of the hotel.",funFact:"Every Haltestelle in Germany has a name. Locals navigate by stop names, not street numbers."},
{type:"mc",q:"Wo ist der Ausgang?",opts:["Er ist dort links.","Er ist ein Geschäft.","Er ist geschlossen.","Er ist ein Eingang."],ans:"Er ist dort links.",hint:"Someone is asking for the exit. Which answer gives a location?"},
{type:"teach",trg:"der Kindergarten",src:"the kindergarten",pos:"noun",gender:"m",note:"COMPOUND: Kinder (children) + Garten (garden).\nMasculine noun. Plural: die Kindergärten. Kinder (children) + Garten (garden).",example:"A: Wo ist der Kindergarten?\nB: Er ist neben der Schule.",exampleSrc:"A: Where is the kindergarten?\nB: It is next to the school.",funFact:"English borrowed this word directly from German! It literally means 'children's garden'."},
{type:"teach",trg:"der Kiosk",src:"the kiosk",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Kioske.",example:"A: Kann ich dort eine Zeitung kaufen?\nB: Ja, am Kiosk.",exampleSrc:"A: Can I buy a newspaper there?\nB: Yes, at the kiosk.",funFact:"German kiosks sell newspapers, snacks, cigarettes, and transit tickets. They are mini convenience stores."},
{type:"teach",trg:"der Laden",src:"the shop, the store",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Läden. More casual than Geschäft.",example:"A: Kennst du den Laden?\nB: Ja, der Laden ist sehr gut.",exampleSrc:"A: Do you know the shop?\nB: Yes, the shop is very good.",funFact:"'Laden' originally meant 'a shutter or plank', because shops used to have wooden shutters you opened for business."},
{type:"teach",trg:"das Lokal",src:"the restaurant, the pub",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Lokale. A casual place to eat or drink.",example:"A: Gibt es hier ein gutes Lokal?\nB: Ja, das Lokal am Platz ist super.",exampleSrc:"A: Is there a good restaurant here?\nB: Yes, the restaurant at the square is great.",funFact:"A 'Stammlokal' is a local pub where regulars always go. Very important in German culture!"},
{type:"teach",trg:"der Ort",src:"the place, the town",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Orte.",example:"A: Was für ein Ort ist das?\nB: Das ist ein kleiner Ort in Bayern.",exampleSrc:"A: What kind of place is that?\nB: That is a small town in Bavaria.",funFact:"Many German town names end in -burg (castle), -dorf (village), or -heim (home)."},
{type:"fb",s:"Die {1} ist vor dem Hotel.",a:["Haltestelle"],opts:["Haltestelle","Kiosk","Laden","Kindergarten"],hint:"This feminine noun is where buses and trams stop.",sSrc:"The bus stop is in front of the hotel."}
]},
{id:"deu_r2l12b",title:"Wo ist das? (Teil 2)",icon:"📍",xp:15,board:true,steps:[
{type:"intro",title:"Wo ist das? (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"das Dorf",src:"the village",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Dörfer.\nSmaller than a Stadt (city) and an Ort (town).",example:"A: Lebst du in der Stadt?\nB: Nein, ich wohne in einem kleinen Dorf.",exampleSrc:"A: Do you live in the city?\nB: No, I live in a small village.",funFact:"Many German town names end in -dorf (Düsseldorf, Neudorf). Dorf literally means a small settlement. Germany has about 80,000 villages, more than any other EU country."},
{type:"teach",trg:"der Platz",src:"the square, the seat",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Plätze. Both a city square and a seat.",example:"A: Ist dieser Platz frei?\nB: Ja, bitte setzen Sie sich.",exampleSrc:"A: Is this seat free?\nB: Yes, please sit down.",funFact:"Alexanderplatz in Berlin is one of Germany's most famous squares, often just called 'Alex'."},
{type:"teach",trg:"die Praxis",src:"the doctor's office",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Praxen.",example:"A: Wo ist die Praxis?\nB: Die Praxis ist im zweiten Stock.",exampleSrc:"A: Where is the doctor's office?\nB: The doctor's office is on the second floor.",funFact:"In Germany, most doctors have their own Praxis (private practice) rather than working in hospitals."},
{type:"teach",trg:"das Schwimmbad",src:"the swimming pool",pos:"noun",gender:"n",note:"COMPOUND: Schwimm (swim) + Bad (bath).\nNeuter noun. Plural: die Schwimmbäder. Schwimmen (swim) + Bad (bath).",example:"A: Gehen wir ins Schwimmbad?\nB: Ja, gute Idee!",exampleSrc:"A: Shall we go to the swimming pool?\nB: Yes, good idea!",funFact:"Germany has over 6,000 public Schwimmbäder. Many towns have both indoor (Hallenbad) and outdoor (Freibad) pools."},
{type:"mc",q:"Wo geht man schwimmen?",opts:["im Schwimmbad","in der Praxis","im Kindergarten","im Lokal"],ans:"im Schwimmbad",hint:"This neuter compound noun combines swimming and bathing."},
{type:"teach",trg:"die Sehenswürdigkeit",src:"the sight, the attraction",pos:"noun",gender:"f",note:"COMPOUND: Sehens (seeing) + Würdig (worthy) + keit (suffix).\nFeminine noun. Plural: die Sehenswürdigkeiten. A famously long German word!",example:"A: Was ist die beste Sehenswürdigkeit?\nB: Das Brandenburger Tor!",exampleSrc:"A: What is the best attraction?\nB: The Brandenburg Gate!",funFact:"Sehenswürdigkeit has 19 letters. It breaks down to sehen (see) + würdig (worthy) + keit (suffix). Literally: a thing worthy of seeing."},
{type:"teach",trg:"die Mitte",src:"the middle, the center",pos:"noun",gender:"f",note:"Feminine noun. No common plural form.",example:"A: Wo liegt das Hotel?\nB: In der Mitte der Stadt.",exampleSrc:"A: Where is the hotel?\nB: In the center of the city.",funFact:"Berlin-Mitte is the central district of Berlin, home to the Reichstag and Museum Island."},
{type:"teach",trg:"die Achtung",src:"attention, caution",pos:"noun",gender:"f",note:"Feminine noun. Very common in announcements.",example:"A: Achtung! Der Zug kommt.\nB: Danke für die Warnung!",exampleSrc:"A: Attention! The train is coming.\nB: Thanks for the warning!",funFact:"You will hear 'Achtung!' in every German train station. It is the universal warning word."},
{type:"teach",trg:"die Information",src:"the information",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Informationen. Also an information desk.",example:"A: Wo ist die Information?\nB: Die Information ist am Eingang.",exampleSrc:"A: Where is the information desk?\nB: The information desk is at the entrance.",funFact:"Germans often abbreviate this to 'Info'. 'Die Info-Tafel' is the information board."},
{type:"fb",s:"{1}! Der Zug kommt.",a:["Achtung"],opts:["Achtung","Mitte","Information","Praxis"],hint:"This word means 'attention' or 'caution' and is heard in stations.",sSrc:"Attention! The train is coming."},
{type:"mc",q:"What does 'die Haltestelle' mean?",opts:["the bakery","the bus stop","the exit","the entrance"],ans:"the bus stop",hint:"Think of a place where vehicles pause to let people on and off."},
{type:"fb",s:"Wo ist der {1}? Ich möchte rausgehen.",a:["Ausgang"],opts:["Ausgang","Eingang","Platz","Laden"],hint:"You want to leave, so you need the way out.",sSrc:"Where is the exit? I want to go outside."},
{type:"mc",q:"Verumius asks: 'Ist dieser Platz frei?' What is he asking about?",opts:["a platform","a shop","a seat","a bakery"],ans:"a seat",hint:"This word has two meanings. Here, someone wants to sit down in a specific spot."},
{type:"match",pairs:[{trg:"die Bäckerei",src:"bakery"},{trg:"der Kindergarten",src:"kindergarten"},{trg:"das Schwimmbad",src:"swimming pool"},{trg:"die Praxis",src:"doctor's office"},{trg:"die Mitte",src:"center"}]},
{type:"mc",q:"Was bedeutet 'das Dorf'?",opts:["the entrance","the stop, the station","the square, the seat","the village"],ans:"the village",hint:"A small rural settlement, smaller than a Stadt (city). Neuter noun."},
{type:"fb",s:"Wie sagt man 'the sight, the attraction' auf Deutsch? {1}",a:["die Sehenswürdigkeit"],opts:["der Ort","der Eingang","die Praxis","die Sehenswürdigkeit"],hint:"A famously long compound: sehen (see) + würdig (worthy) + -keit (noun suffix).",sSrc:"How do you say 'the sight, the attraction' in German?"}
]},

{id:"deu_r2l13",title:"Unterwegs",icon:"🚌",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs",desc:"Verumius is navigating Berlin's famous transit system. Learn words for transport, directions, and getting around the city.",goals:["Learn 20 transport and direction words","Use compass directions: Norden, Süden, Osten, Westen","Understand contractions like am and ins"]},
{type:"teach",trg:"der Anschluss",src:"the connection (transit)",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Anschlüsse. A connecting train or bus.",example:"A: Habe ich Anschluss nach München?\nB: Ja, der Anschluss ist in zehn Minuten.",exampleSrc:"A: Do I have a connection to Munich?\nB: Yes, the connection is in ten minutes.",funFact:"Missing your Anschluss is a real fear for German commuters. The phrase is 'den Anschluss verpassen'."},
{type:"teach",trg:"die Autobahn",src:"the highway, the motorway",pos:"noun",gender:"f",note:"COMPOUND: Auto (car) + Bahn (track).\nFeminine noun. Plural: die Autobahnen. Auto (car) + Bahn (way).",example:"A: Fahren wir über die Autobahn?\nB: Ja, das ist schneller.",exampleSrc:"A: Are we taking the highway?\nB: Yes, that is faster.",funFact:"Some sections of the German Autobahn have no speed limit. The recommended speed is 130 km/h."},
{type:"teach",trg:"die Bahn",src:"the railway, the train",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Bahnen. Short for Eisenbahn (iron way).",example:"A: Fährst du mit der Bahn?\nB: Ja, ich fahre mit der Bahn nach Hamburg.",exampleSrc:"A: Are you going by train?\nB: Yes, I am going by train to Hamburg.",funFact:"Deutsche Bahn (DB) is Germany's national railway. Germans love to joke about its delays."},
{type:"teach",trg:"der Fahrer",src:"the driver",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Fahrer. From fahren (to drive).",example:"A: Wer ist der Fahrer?\nB: Der Fahrer heißt Thomas.",exampleSrc:"A: Who is the driver?\nB: The driver's name is Thomas.",funFact:"A 'Busfahrer' is a bus driver, a 'Taxifahrer' is a taxi driver. German loves compound nouns!"},
{type:"teach",trg:"das Fahrrad",src:"the bicycle",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Fahrräder. Fahr (drive/ride) + Rad (wheel).",example:"A: Hast du ein Fahrrad?\nB: Ja, ich fahre jeden Tag mit dem Fahrrad.",exampleSrc:"A: Do you have a bicycle?\nB: Yes, I ride my bicycle every day.",funFact:"Germany has over 75,000 km of bike paths. Many cities have more cyclists than drivers."},
{type:"match",pairs:[{trg:"die Autobahn",src:"the highway, the motorway"},{trg:"die Bahn",src:"the railway, the train"},{trg:"der Fahrer",src:"the driver"},{trg:"das Fahrrad",src:"the bicycle"}]},
{type:"teach",trg:"das Gleis",src:"the track, the platform",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Gleise. Used at train stations.",example:"A: Von welchem Gleis fährt der Zug?\nB: Von Gleis fünf.",exampleSrc:"A: From which track does the train leave?\nB: From track five.",funFact:"Gleis and Bahnsteig both refer to platforms, but Gleis focuses on the track number."},
{type:"teach",trg:"der Lkw",src:"the truck",pos:"noun",gender:"m",note:"Masculine noun. Short for Lastkraftwagen (load-power-vehicle).",example:"A: Was ist das?\nB: Das ist ein großer Lkw.",exampleSrc:"A: What is that?\nB: That is a big truck.",funFact:"Lastkraftwagen has 15 letters. No wonder Germans abbreviate it to Lkw!"},
{type:"teach",trg:"die S-Bahn",src:"the city train, the commuter rail",pos:"noun",gender:"f",note:"Feminine noun. S stands for Schnell (fast) or Stadt (city).",example:"A: Nehmen wir die S-Bahn?\nB: Ja, die S-Bahn ist schneller als der Bus.",exampleSrc:"A: Shall we take the S-Bahn?\nB: Yes, the S-Bahn is faster than the bus.",funFact:"Berlin's S-Bahn ring (Ringbahn) goes in a circle around the city. Locals call it 'der Ring'."},
{type:"teach",trg:"die Straßenbahn",src:"the tram, the streetcar",pos:"noun",gender:"f",note:"COMPOUND: Straße (street) + Bahn (track/railway).\nFeminine noun. Plural: die Straßenbahnen. Straße (street) + Bahn (way).",example:"A: Fährt hier eine Straßenbahn?\nB: Ja, die Straßenbahn kommt alle zehn Minuten.",exampleSrc:"A: Does a tram run here?\nB: Yes, the tram comes every ten minutes.",funFact:"Berlin removed its trams in the west during the Cold War but kept them in the east. They are back everywhere now."},
{type:"teach",trg:"der Norden",src:"the north",pos:"noun",gender:"m",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt Hamburg?\nB: Hamburg liegt im Norden.",exampleSrc:"A: Where is Hamburg?\nB: Hamburg is in the north.",funFact:"Northern Germany (Norddeutschland) is flat and windy. People there are known for being direct and dry-humored."},
{type:"match",pairs:[{trg:"der Lkw",src:"the truck"},{trg:"die S-Bahn",src:"the city train, the commuter rail"},{trg:"die Straßenbahn",src:"the tram, the streetcar"},{trg:"der Norden",src:"the north"}]},
{type:"teach",trg:"der Süden",src:"the south",pos:"noun",gender:"m",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt München?\nB: München liegt im Süden.",exampleSrc:"A: Where is Munich?\nB: Munich is in the south.",funFact:"Southern Germany (Bayern and Baden-Württemberg) has mountains, beer gardens, and a very distinct dialect."},
{type:"teach",trg:"der Osten",src:"the east",pos:"noun",gender:"m",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt Dresden?\nB: Dresden liegt im Osten.",exampleSrc:"A: Where is Dresden?\nB: Dresden is in the east.",funFact:"After reunification in 1990, Germans still say 'im Osten' and 'im Westen' to refer to the former East and West."},
{type:"teach",trg:"der Westen",src:"the west",pos:"noun",gender:"m",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt Köln?\nB: Köln liegt im Westen.",exampleSrc:"A: Where is Cologne?\nB: Cologne is in the west.",funFact:"Cologne (Köln) in western Germany is famous for its cathedral and its own beer style, Kölsch."},
{type:"teach",trg:"am",src:"at the (contraction of an + dem)",pos:"prep",gender:null,note:"Preposition+article contraction. Used for locations and days.",example:"A: Wo treffen wir uns?\nB: Am Bahnhof, am Montag.",exampleSrc:"A: Where do we meet?\nB: At the train station, on Monday.",funFact:"'Am' is used with days (am Montag), times (am Morgen), and places (am Flughafen)."},
{type:"teach",trg:"ins",src:"into the (contraction of in + das)",pos:"prep",gender:null,note:"Preposition+article contraction. Used with neuter nouns for direction.",example:"A: Wohin gehst du?\nB: Ich gehe ins Kino.",exampleSrc:"A: Where are you going?\nB: I am going to the cinema.",funFact:"Ins Kino, ins Theater, ins Museum. These are the classic 'ins' phrases every German learner needs."},
{type:"match",pairs:[{trg:"der Osten",src:"the east"},{trg:"der Westen",src:"the west"},{trg:"am",src:"at the (contraction of an + dem)"},{trg:"ins",src:"into the (contraction of in + das)"}]}]},
{id:"deu_r2l13b",title:"Unterwegs (Teil 2)",icon:"🚌",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"hoch",src:"high, tall",pos:"adj",gender:null,note:"Adjective/adverb. Describes height or elevation.",example:"A: Ist der Turm hoch?\nB: Ja, er ist sehr hoch.",exampleSrc:"A: Is the tower tall?\nB: Yes, it is very tall.",funFact:"The Zugspitze (2,962 m) is Germany's highest mountain. 'Hoch' describes its peak perfectly."},
{type:"teach",trg:"weit",src:"far, wide",pos:"adj",gender:null,note:"Adjective/adverb. Used for distance. Opposite: nah (near).",example:"A: Ist der Bahnhof weit?\nB: Nein, nur fünf Minuten zu Fuß.",exampleSrc:"A: Is the train station far?\nB: No, only five minutes on foot.",funFact:"'Wie weit ist es?' (How far is it?) is the essential travel question in Germany."},
{type:"teach",trg:"so",src:"so, such, like this",pos:"adv",gender:null,note:"Adverb. Very versatile. Used for emphasis and comparison.",example:"A: Berlin ist so groß!\nB: Ja, die Stadt ist wirklich so groß.",exampleSrc:"A: Berlin is so big!\nB: Yes, the city is really that big.",funFact:"'So' is one of the most overused filler words in German. 'Also, so, ja...' starts many sentences."},
{type:"teach",trg:"all",src:"all, every",pos:"pron",gender:null,note:"Pronoun/determiner. Changes form: alle (plural), alles (everything).",example:"A: Sind alle da?\nB: Ja, alle sind da.",exampleSrc:"A: Is everyone here?\nB: Yes, everyone is here.",funFact:"'Alles klar?' (All clear? / Everything okay?) is an extremely common German greeting and check-in phrase."},
{type:"teach",trg:"daneben",src:"next to it, beside it",pos:"adv",gender:null,note:"Adverb. Combines da (there) + neben (next to).",example:"A: Wo ist die Apotheke?\nB: Siehst du das Geschäft? Daneben.",exampleSrc:"A: Where is the pharmacy?\nB: Do you see the shop? Next to it.",funFact:"German has many da- words: daneben, davor, dahinter, darüber. They all mean 'there + preposition'."},
{type:"match",pairs:[{trg:"weit",src:"far, wide"},{trg:"so",src:"so, such, like this"},{trg:"all",src:"all, every"},{trg:"daneben",src:"next to it, beside it"}]},
{type:"teach",trg:"oben",src:"up, above, upstairs",pos:"adv",gender:null,note:"Adverb of place. Indicates a higher position.\nOpposite: unten (below).",example:"A: Wo ist das Restaurant?\nB: Oben, im zweiten Stock.",exampleSrc:"A: Where is the restaurant?\nB: Upstairs, on the second floor.",funFact:"Oben forms many compound words: obendran (on top of that), obenauf (on top), nach oben (upward). Germans love stacking spatial meaning."},
{type:"teach",trg:"unten",src:"down, below, downstairs",pos:"adv",gender:null,note:"Adverb of place. Indicates a lower position.\nOpposite: oben (above).",example:"A: Wo ist der Ausgang?\nB: Unten, neben dem Eingang.",exampleSrc:"A: Where is the exit?\nB: Downstairs, next to the entrance.",funFact:"Unten is the spatial opposite of oben. Together they cover vertical orientation. U-Bahn is literally Untergrundbahn: underground railway."},
{type:"teach",trg:"hinten",src:"behind, at the back",pos:"adv",gender:null,note:"Adverb of place. Refers to the back position.\nOpposite: vorne (in front).",example:"A: Wo sitzt du im Bus?\nB: Hinten, am Fenster.",exampleSrc:"A: Where do you sit on the bus?\nB: At the back, by the window.",funFact:"Hinter (behind, preposition) and hinten (at the back, adverb) come from the same root. The -en ending turns the preposition into a location adverb."},
{type:"teach",trg:"draußen",src:"outside",pos:"adv",gender:null,note:"Adverb of place. Indicates being outside.\nOpposite: drinnen (inside).",example:"A: Wo ist Lukas?\nB: Draußen, er wartet vor dem Hotel.",exampleSrc:"A: Where is Lukas?\nB: Outside, he is waiting in front of the hotel.",funFact:"Draußen and drinnen are perfect opposites. 'Draußen vor der Tür' is the title of a famous German post-war play. Draußen always carries a sense of separation."},
{type:"teach",trg:"dort",src:"there (at a distance)",pos:"adv",gender:null,note:"Adverb of place. More specific than da (there).\nDort drüben = over there.",example:"A: Wo ist der Bahnhof?\nB: Dort, am Ende der Straße.",exampleSrc:"A: Where is the train station?\nB: There, at the end of the street.",funFact:"Dort is more precise than da. Da = there (neutral). Dort = there (at a specific, visible location). 'Dort drüben' means over there and is very common in directions."},
{type:"match",pairs:[{trg:"unten",src:"down, below, downstairs"},{trg:"hinten",src:"behind, at the back"},{trg:"draußen",src:"outside"},{trg:"dort",src:"there (at a distance)"}]},
{type:"teach",trg:"zurück",src:"back, backwards",pos:"adv",gender:null,note:"Adverb of direction. Means going back to a previous position.\nGehen Sie zurück = go back.",example:"A: Ich bin gleich zurück.\nB: Okay, ich warte hier.",exampleSrc:"A: I will be right back.\nB: Okay, I will wait here.",funFact:"Zurück is one of the most common German words for travelers. Rückfahrkarte (return ticket) has zurück hidden in Rück-. Hin und zurück = there and back."},
{type:"mc",q:"What does 'die Straßenbahn' mean?",opts:["the tram","the highway","the bicycle","the truck"],ans:"the tram",hint:"It rides on streets and runs on rails."},
{type:"fb",s:"Ich gehe {1} Kino.",a:["ins"],opts:["ins","am","auf","im"],hint:"You are going INTO a neuter place.",sSrc:"I am going to the cinema."},
{type:"mc",q:"Hamburg liegt im... ?",opts:["Süden","Norden","Osten","Westen"],ans:"Norden",hint:"This port city is near the coast of the North Sea."},
{type:"match",pairs:[{trg:"das Fahrrad",src:"bicycle"},{trg:"die Autobahn",src:"highway"},{trg:"das Gleis",src:"track"},{trg:"die S-Bahn",src:"city train"},{trg:"der Lkw",src:"truck"}]},
{type:"mc",q:"Was bedeutet 'hoch'?",opts:["the driver","the railway, the train","high, tall","the connection (transit)"],ans:"high, tall",hint:"An adjective for vertical height. Think 'Hochhaus' (skyscraper) or 'Hochzeit' (wedding)."},
{type:"fb",s:"Ist der Bahnhof {1}?",a:["weit"],opts:["das Gleis","die Autobahn","weit","der Süden"],hint:"An adjective asking about distance. Opposite of 'nah' (near).",sSrc:"Is the train station far?"},
{type:"mc",q:"Was bedeutet 'so'?",opts:["the west","the truck","the north","so, such, like this"],ans:"so, such, like this",hint:"A tiny but powerful adverb. Same spelling and meaning as English 'so.'"},
{type:"fb",s:"Sind {1}e da?",a:["all"],opts:["all","das Gleis","der Süden","der Norden"],hint:"A short word meaning 'every' or 'everyone.' Same root as English 'all.'",sSrc:"Is everyone here?"},
{type:"mc",q:"Was bedeutet 'daneben'?",opts:["next to it, beside it","so, such, like this","all, every","the driver"],ans:"next to it, beside it",hint:"A compound adverb: 'da' (there) + 'neben' (alongside). Describes a nearby position."},
{type:"fb",s:"{1}, im zweiten Stock.",a:["oben"],opts:["das Fahrrad","am","oben","hinten"],hint:"The adverb for 'up' or 'upstairs.' Opposite of 'unten' (below).",sSrc:"Upstairs, on the second floor."},
{type:"mc",q:"Was bedeutet 'unten'?",opts:["back, backwards","down, below, downstairs","the tram, the streetcar","high, tall"],ans:"down, below, downstairs",hint:"The directional adverb for the low end. Related to English 'under.'"},
{type:"fb",s:"{1}, am Fenster.",a:["hinten"],opts:["der Lkw","so","all","hinten"],hint:"The adverb for 'at the back' or 'in the rear.' Related to 'hinter' (behind).",sSrc:"At the back, by the window."},
{type:"mc",q:"Was bedeutet 'draußen'?",opts:["the tram, the streetcar","there (at a distance)","outside","the track, the platform"],ans:"outside",hint:"Where you are when you leave a building. Opposite of 'drinnen' (inside)."},
{type:"fb",s:"{1}, am Ende der Straße.",a:["dort"],opts:["dort","der Süden","die Autobahn","der Norden"],hint:"A demonstrative adverb pointing to a location at some distance. Formal cousin of 'da.'",sSrc:"There, at the end of the street."},
{type:"mc",q:"Was bedeutet 'zurück'?",opts:["up, above, upstairs","the track, the platform","the bicycle","back, backwards"],ans:"back, backwards",hint:"A directional adverb meaning return. 'Zu' (to) + 'rück' (rear). Also a common prefix."}
]},

{id:"deu_r2l14",title:"Kommen und Gehen",icon:"🚶",xp:15,board:true,steps:[
{type:"intro",title:"Kommen und Gehen",desc:"Verumius is always on the move in Berlin. Learn the verbs for coming, going, searching, and everything in between.",goals:["Learn 18 movement and action verbs","Use separable verbs like abholen, mitkommen, umsteigen","Talk about travel actions and plans"]},
{type:"teach",trg:"abfliegen",src:"to depart (by plane)",pos:"verb",gender:null,note:"Separable verb: ab + fliegen. Ich fliege morgen ab.",example:"A: Wann fliegst du ab?\nB: Ich fliege um acht Uhr ab.",exampleSrc:"A: When do you depart?\nB: I depart at eight o'clock.",funFact:"At German airports, 'Abflug' (departure) boards are yellow. 'Ankunft' (arrival) boards are white."},
{type:"teach",trg:"abholen",src:"to pick up (a person or thing)",pos:"verb",gender:null,note:"Separable verb: ab + holen. Ich hole dich ab.",example:"A: Kannst du mich abholen?\nB: Ja, ich hole dich am Bahnhof ab.",exampleSrc:"A: Can you pick me up?\nB: Yes, I will pick you up at the station.",funFact:"Germans are punctual about Abholen. If they say 15:00, they mean 15:00, not 15:05."},
{type:"teach",trg:"besichtigen",src:"to visit, to tour (a place)",pos:"verb",gender:null,note:"Inseparable verb. Wir besichtigen das Schloss.",example:"A: Was machen wir heute?\nB: Wir besichtigen das Brandenburger Tor.",exampleSrc:"A: What are we doing today?\nB: We are visiting the Brandenburg Gate.",funFact:"Besichtigen is more formal than besuchen. You besichtigen monuments but besuchen friends."},
{type:"teach",trg:"halten",src:"to hold, to stop",pos:"verb",gender:null,note:"Strong verb: er hält. Also used for buses: Der Bus hält hier.",example:"A: Hält der Bus hier?\nB: Ja, der Bus hält an dieser Haltestelle.",exampleSrc:"A: Does the bus stop here?\nB: Yes, the bus stops at this stop.",funFact:"'Halt!' on its own means 'Stop!' It is used by police and in everyday speech."},
{type:"teach",trg:"stehen",src:"to stand",pos:"verb",gender:null,note:"Irregular verb. Ich stehe, du stehst, er steht.",example:"A: Wo stehst du?\nB: Ich stehe vor dem Bahnhof.",exampleSrc:"A: Where are you standing?\nB: I am standing in front of the train station.",funFact:"'Wie steht es?' literally means 'How does it stand?' but it means 'What is the score?' or 'How are things?'"},
{type:"fb",s:"Der Bus {1} an der Haltestelle.",a:["hält"],opts:["hält","steht","bleibt","fährt"],hint:"Which verb means the bus STOPS at the stop?",sSrc:"The bus stops at the bus stop."},
{type:"teach",trg:"suchen",src:"to search, to look for",pos:"verb",gender:null,note:"Regular verb. Ich suche, du suchst.",example:"A: Was suchst du?\nB: Ich suche den Ausgang.",exampleSrc:"A: What are you looking for?\nB: I am looking for the exit.",funFact:"Google's German slogan was once 'Gut gesucht ist halb gefunden' (Well searched is half found)."},
{type:"teach",trg:"wandern",src:"to hike",pos:"verb",gender:null,note:"Regular verb. Ich wandere, du wanderst.",example:"A: Gehst du gern wandern?\nB: Ja, ich wandere jedes Wochenende.",exampleSrc:"A: Do you like hiking?\nB: Yes, I hike every weekend.",funFact:"Germany has over 200,000 km of marked hiking trails. Wandern is a national passion."},
{type:"teach",trg:"bleiben",src:"to stay, to remain",pos:"verb",gender:null,note:"Irregular verb. Ich bleibe, du bleibst. Past: geblieben.",example:"A: Wie lange bleibst du in Berlin?\nB: Ich bleibe drei Tage.",exampleSrc:"A: How long are you staying in Berlin?\nB: I am staying three days.",funFact:"'Bleib gesund!' (Stay healthy!) became a very popular farewell during the pandemic years."},
{type:"teach",trg:"dauern",src:"to last, to take (time)",pos:"verb",gender:null,note:"Regular verb. Es dauert zwei Stunden.",example:"A: Wie lange dauert die Fahrt?\nB: Sie dauert eine Stunde.",exampleSrc:"A: How long does the trip take?\nB: It takes one hour.",funFact:"'Das dauert ewig!' (That takes forever!) is a common complaint, especially about bureaucracy."},
{type:"teach",trg:"helfen",src:"to help",pos:"verb",gender:null,note:"Strong verb: er hilft (stem changes e to i). Takes dative.",example:"A: Können Sie mir helfen?\nB: Ja, natürlich. Wie kann ich helfen?",exampleSrc:"A: Can you help me?\nB: Yes, of course. How can I help?",funFact:"'Hilfe!' (Help!) is the German emergency shout. You will hear it in every action movie dubbed into German."},
{type:"mc",q:"Wie lange ___ du in Berlin?",opts:["bleibst","dauerst","hilfst","durchsuchst"],ans:"bleibst",hint:"This verb means to stay or remain somewhere."}
]},
{id:"deu_r2l14b",title:"Kommen und Gehen (Teil 2)",icon:"🚶",xp:15,board:true,steps:[
{type:"intro",title:"Kommen und Gehen (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"leihen",src:"to lend, to borrow",pos:"verb",gender:null,note:"Strong verb. Ich leihe dir mein Buch. Context determines lend vs. borrow.",example:"A: Kannst du mir dein Handy leihen?\nB: Ja, hier bitte.",exampleSrc:"A: Can you lend me your phone?\nB: Yes, here you go.",funFact:"German uses the same word for lend AND borrow. Context makes the meaning clear."},
{type:"teach",trg:"mitkommen",src:"to come along",pos:"verb",gender:null,note:"Separable verb: mit + kommen. Kommst du mit?",example:"A: Ich gehe ins Museum. Kommst du mit?\nB: Ja, ich komme gern mit!",exampleSrc:"A: I am going to the museum. Are you coming along?\nB: Yes, I would love to come along!",funFact:"'Kommst du mit?' is one of the most common German invitations. Short, direct, friendly."},
{type:"teach",trg:"zeigen",src:"to show",pos:"verb",gender:null,note:"Regular verb. Ich zeige, du zeigst.",example:"A: Können Sie mir den Weg zeigen?\nB: Ja, ich zeige Ihnen den Weg.",exampleSrc:"A: Can you show me the way?\nB: Yes, I will show you the way.",funFact:"'Zeig mal!' (Show me!) is how Germans ask to see something. Very direct and casual."},
{type:"teach",trg:"mitnehmen",src:"to take along",pos:"verb",gender:null,note:"Separable verb: mit + nehmen. Er nimmt mich mit.",example:"A: Nimmst du den Regenschirm mit?\nB: Ja, ich nehme ihn mit.",exampleSrc:"A: Are you taking the umbrella along?\nB: Yes, I am taking it along.",funFact:"'Zum Mitnehmen' means 'to go' for food. 'Hier essen oder mitnehmen?' is the German 'for here or to go?'"},
{type:"fb",s:"Kommst du {1}? Ich gehe ins Museum.",a:["mit"],opts:["mit","ab","aus","ein"],hint:"This separable prefix indicates accompaniment or joining someone.",sSrc:"Are you coming along? I am going to the museum."},
{type:"teach",trg:"weiterfahren",src:"to continue driving, to drive on",pos:"verb",gender:null,note:"Separable verb: weiter + fahren. Wir fahren weiter.",example:"A: Steigen wir hier aus?\nB: Nein, wir fahren weiter bis Alexanderplatz.",exampleSrc:"A: Do we get off here?\nB: No, we continue to Alexanderplatz.",funFact:"Weiter means 'further'. Germans add it to many verbs: weitergehen (walk on), weitermachen (continue)."},
{type:"teach",trg:"umsteigen",src:"to transfer, to change (trains/buses)",pos:"verb",gender:null,note:"Separable verb: um + steigen. Sie steigen in Frankfurt um.",example:"A: Muss ich umsteigen?\nB: Ja, Sie steigen in Hauptbahnhof um.",exampleSrc:"A: Do I have to transfer?\nB: Yes, you transfer at the main station.",funFact:"Umsteigen is a survival word for German public transit. Every journey planner shows where to transfer."},
{type:"teach",trg:"auf sein",src:"to be open",pos:"verb",gender:null,note:"Separable: Das Geschäft ist auf. Colloquial for 'offen sein'.",example:"A: Ist die Bäckerei auf?\nB: Ja, sie ist bis sechs auf.",exampleSrc:"A: Is the bakery open?\nB: Yes, it is open until six.",funFact:"'Auf' here means open. 'Zu' means closed. 'Die Tür ist auf/zu' (The door is open/closed)."},
{type:"mc",q:"Ist die Bäckerei ___?",opts:["auf","um","ein","ab"],ans:"auf",hint:"You want to know if the bakery is OPEN for business."},
{type:"teach",trg:"grade",src:"just, right now (colloquial)",pos:"adv",gender:null,note:"Colloquial form of 'gerade'. Very common in spoken German.",example:"A: Was machst du grade?\nB: Ich bin grade am Bahnhof.",exampleSrc:"A: What are you doing right now?\nB: I am at the train station right now.",funFact:"'Gerade' is the standard form, but 'grade' is what you hear in casual Berlin speech."},
{type:"mc",q:"What does 'umsteigen' mean?",opts:["to arrive there","to transfer","to search around","to depart early"],ans:"to transfer",hint:"You leave one train and get on another one."},
{type:"fb",s:"Wie lange {1} die Fahrt nach Hamburg?",a:["dauert"],opts:["dauert","bleibt","hilft","sucht"],hint:"You are asking about how much time the trip takes.",sSrc:"How long does the trip to Hamburg take?"},
{type:"mc",q:"'Kommst du mit?' is an invitation to... ?",opts:["go away alone","be quiet about it","come along","stay home instead"],ans:"come along",hint:"The speaker wants company on their outing."},
{type:"match",pairs:[{trg:"abholen",src:"to pick up"},{trg:"bleiben",src:"to stay"},{trg:"wandern",src:"to hike"},{trg:"suchen",src:"to search"},{trg:"helfen",src:"to help"}]},
{type:"mc",q:"Was bedeutet 'leihen'?",opts:["to stay, to remain","to help","to depart (by plane)","to lend, to borrow"],ans:"to lend, to borrow",hint:"A verb for temporary exchange of objects. Think of a 'Leihwagen' (rental car)."},
{type:"fb",s:"Wie sagt man 'to come along' auf Deutsch? {1}",a:["mitkommen"],opts:["wandern","mitkommen","grade","halten"],hint:"A separable verb: 'mit' (with/along) + 'kommen' (to come). 'Kommst du mit?'",sSrc:"How do you say 'to come along' in German?"},
{type:"mc",q:"Was bedeutet 'zeigen'?",opts:["to show","to transfer, to change (trains/buses)","to lend, to borrow","to hold, to stop"],ans:"to show",hint:"You point your finger and do this. Related to 'der Zeiger' (pointer/hand on a clock)."},
{type:"fb",s:"Wie sagt man 'to take along' auf Deutsch? {1}",a:["mitnehmen"],opts:["mitnehmen","abholen","auf sein","helfen"],hint:"A separable verb: 'mit' (with/along) + 'nehmen' (to take). Pack it and bring it!",sSrc:"How do you say 'to take along' in German?"},
{type:"mc",q:"Was bedeutet 'weiterfahren'?",opts:["to hike","to continue driving, to drive on","to lend, to borrow","to hold, to stop"],ans:"to continue driving, to drive on",hint:"A separable compound: 'weiter' (further) + 'fahren' (to go by vehicle). Keep going!"},
{type:"fb",s:"Wie sagt man 'to be open' auf Deutsch? {1}",a:["auf sein"],opts:["weiterfahren","abfliegen","zeigen","auf sein"],hint:"Two words: a directional prefix meaning 'open/up' + the verb 'to be.' A shop can be this.",sSrc:"How do you say 'to be open' in German?"},
{type:"mc",q:"Was bedeutet 'grade'?",opts:["to stand","to last, to take (time)","just, right now (colloquial)","to stay, to remain"],ans:"just, right now (colloquial)",hint:"Informal shortening of 'gerade.' Describes something happening at this very moment."}
]},

{id:"deu_r2l15",title:"Rund um die Stadt",icon:"🏙️",xp:15,board:true,steps:[
{type:"intro",title:"Rund um die Stadt",desc:"Verumius is becoming a true Berlin explorer. Learn words for sights, information, nature, and everything you need as a tourist.",goals:["Learn 20 city and tourism vocabulary words","Ask for help and information confidently","Describe sights, views, and places"]},
{type:"teach",trg:"der Blick",src:"the view, the glance",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Blicke.",example:"A: Wie ist der Blick von hier?\nB: Der Blick ist fantastisch!",exampleSrc:"A: How is the view from here?\nB: The view is fantastic!",funFact:"'Auf den ersten Blick' means 'at first glance'. It is also the German title of the movie 'Love at First Sight'."},
{type:"teach",trg:"die Hilfe",src:"the help",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Hilfen.",example:"A: Brauchst du Hilfe?\nB: Ja, ich brauche Hilfe mit der Karte.",exampleSrc:"A: Do you need help?\nB: Yes, I need help with the map.",funFact:"'Erste Hilfe' means 'first aid'. Every German driver must carry a first aid kit in their car by law."},
{type:"teach",trg:"die Ansage",src:"the announcement",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Ansagen. An + Sage (saying).",example:"A: Hast du die Ansage gehört?\nB: Ja, der Zug hat Verspätung.",exampleSrc:"A: Did you hear the announcement?\nB: Yes, the train is delayed.",funFact:"Train announcements in Germany always start with 'Meine Damen und Herren' (Ladies and gentlemen)."},
{type:"teach",trg:"die Auskunft",src:"the information, the information desk",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Auskünfte. Aus (out) + Kunft (coming).",example:"A: Wo bekomme ich Informationen?\nB: Fragen Sie an der Auskunft.",exampleSrc:"A: Where can I get information?\nB: Ask at the information desk.",funFact:"'Telefonauskunft' was the phone directory service. Before smartphones, you called 11833 for any number."},
{type:"teach",trg:"das Beispiel",src:"the example",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Beispiele. Bei (by) + Spiel (play).",example:"A: Kannst du mir ein Beispiel geben?\nB: Ja, zum Beispiel das hier.",exampleSrc:"A: Can you give me an example?\nB: Yes, for example this one.",funFact:"'Zum Beispiel' (for example), abbreviated 'z.B.', is one of the most common phrases in written German."},
{type:"match",pairs:[{trg:"die Hilfe",src:"the help"},{trg:"die Ansage",src:"the announcement"},{trg:"die Auskunft",src:"the information, the information desk"},{trg:"das Beispiel",src:"the example"}]},
{type:"teach",trg:"die Durchsage",src:"the PA announcement",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Durchsagen. Durch (through) + Sage (saying).",example:"A: Was war das?\nB: Das war eine Durchsage. Der Zug kommt später.",exampleSrc:"A: What was that?\nB: That was an announcement. The train is coming later.",funFact:"Durchsage literally means 'saying through' because the message goes through the speaker system."},
{type:"fb",s:"Kannst du mir ein {1} geben?",a:["Beispiel"],opts:["Beispiel","Blick","Ausflug","Foto"],hint:"You are asking for an illustration or sample to explain something.",sSrc:"Can you give me an example?"},
{type:"teach",trg:"das Schild",src:"the sign",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Schilder.",example:"A: Was steht auf dem Schild?\nB: Auf dem Schild steht: Ausgang.",exampleSrc:"A: What does the sign say?\nB: The sign says: Exit.",funFact:"German road signs follow strict color rules: blue for highways, yellow for federal roads, white for city streets."},
{type:"teach",trg:"die Vorsicht",src:"the caution, the care",pos:"noun",gender:"f",note:"Feminine noun. No common plural. Vor (before) + Sicht (sight).",example:"A: Vorsicht! Die Straße ist nass.\nB: Danke, ich passe auf.",exampleSrc:"A: Careful! The street is wet.\nB: Thanks, I will be careful.",funFact:"'Vorsicht, Stufe!' (Caution, step!) is written on almost every doorstep in Germany."},
{type:"teach",trg:"das Meer",src:"the sea",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Meere.",example:"A: Warst du schon am Meer?\nB: Ja, die Nordsee ist wunderschön.",exampleSrc:"A: Have you been to the sea?\nB: Yes, the North Sea is beautiful.",funFact:"Germany has two seas: the Nordsee (North Sea) and the Ostsee (Baltic Sea). Both are popular vacation spots."},
{type:"teach",trg:"der See",src:"the lake",pos:"noun",gender:"m",note:"Masculine noun! Plural: die Seen. Not the same as 'die See' (the sea).",example:"A: Gehen wir zum See?\nB: Ja, der See ist sehr schön.",exampleSrc:"A: Shall we go to the lake?\nB: Yes, the lake is very beautiful.",funFact:"Watch out! 'Der See' (masculine) = lake. 'Die See' (feminine) = sea. Same spelling, different genders, different meanings!"},
{type:"teach",trg:"der Ausflug",src:"the excursion, the day trip",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Ausflüge. Aus (out) + Flug (flight).",example:"A: Machen wir einen Ausflug?\nB: Ja, wir machen einen Ausflug nach Potsdam.",exampleSrc:"A: Shall we take a day trip?\nB: Yes, we are taking a day trip to Potsdam.",funFact:"Day trips (Ausflüge) from Berlin to Potsdam, Spreewald, or Sachsenhausen are very popular."},
{type:"mc",q:"'Der See' ist maskulin und bedeutet...",opts:["the lake","the sea","the river","the ocean"],ans:"the lake",hint:"This masculine noun refers to a body of fresh water, often surrounded by land."}
,
{"type":"mc","q":"Was ist 'die Ansage'?","opts":["the announcement","the question","the ticket","the platform"],"ans":"the announcement","hint":"Information shared publicly to a group."},
{"type":"fb","s":"Bitte beachten Sie die {1}.","a":["Durchsage"],"opts":["Durchsage","Fahrkarte","Haltestelle","Ausfahrt"],"hint":"A spoken message over speakers at a station.","sSrc":"Please pay attention to the PA announcement."}]},
{id:"deu_r2l15b",title:"Rund um die Stadt (Teil 2)",icon:"🏙️",xp:15,board:true,steps:[
{type:"intro",title:"Rund um die Stadt (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"das Foto",src:"the photo",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Fotos.",example:"A: Kann ich ein Foto machen?\nB: Ja, natürlich! Lächeln!",exampleSrc:"A: Can I take a photo?\nB: Yes, of course! Smile!",funFact:"Germans say 'ein Foto machen' (make a photo), not 'take a photo'. Different verb, same action!"},
{type:"teach",trg:"die Führung",src:"the guided tour",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Führungen. From führen (to lead).",example:"A: Gibt es eine Führung?\nB: Ja, die Führung beginnt um elf Uhr.",exampleSrc:"A: Is there a guided tour?\nB: Yes, the tour starts at eleven o'clock.",funFact:"Free walking tours (kostenlose Führungen) are popular in Berlin. You just give a tip at the end."},
{type:"teach",trg:"die Karte",src:"the map, the ticket, the card",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Karten. Context determines meaning.",example:"A: Hast du eine Karte?\nB: Ja, ich habe eine Karte von Berlin.",exampleSrc:"A: Do you have a map?\nB: Yes, I have a map of Berlin.",funFact:"Karte means map, ticket, AND card. 'Fahrkarte' = transit ticket. 'Eintrittskarte' = admission ticket. 'Kreditkarte' = credit card."},
{type:"teach",trg:"der Prospekt",src:"the brochure, the flyer",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Prospekte.",example:"A: Haben Sie einen Prospekt?\nB: Ja, hier ist der Prospekt vom Museum.",exampleSrc:"A: Do you have a brochure?\nB: Yes, here is the museum brochure.",funFact:"Tourist information centers in Germany always have stacks of free Prospekte for every attraction."},
{type:"teach",trg:"das Reisebüro",src:"the travel agency",pos:"noun",gender:"n",note:"COMPOUND: Reise (travel) + Büro (office).\nNeuter noun. Plural: die Reisebüros. Reise (travel) + Büro (office).",example:"A: Wo buche ich die Reise?\nB: Im Reisebüro am Platz.",exampleSrc:"A: Where do I book the trip?\nB: At the travel agency at the square.",funFact:"Despite the internet, Germany still has thousands of Reisebüros. Many Germans prefer booking trips in person."},
{type:"fb",s:"Kann ich ein {1} machen?",a:["Foto"],opts:["Foto","Karte","Schild","Führung"],hint:"You want to take a picture. Germans say 'make' a photo, not 'take'.",sSrc:"Can I take a photo?"},
{type:"teach",trg:"der Reiseführer",src:"the travel guide (book or person)",pos:"noun",gender:"m",note:"COMPOUND: Reise (travel) + Führer (guide).\nMasculine noun. Plural: die Reiseführer. Reise (travel) + Führer (guide).",example:"A: Hast du einen Reiseführer?\nB: Ja, der Reiseführer empfiehlt dieses Lokal.",exampleSrc:"A: Do you have a travel guide?\nB: Yes, the guide recommends this restaurant.",funFact:"The Lonely Planet and Baedeker travel guides were pioneers. Baedeker, founded in 1827 in Germany, invented the modern guidebook."},
{type:"teach",trg:"ander",src:"other, different",pos:"adj",gender:null,note:"Pronoun/adjective. Changes form: der andere, die andere, das andere.",example:"A: Möchtest du dieses Hotel?\nB: Nein, das andere Hotel ist besser.",exampleSrc:"A: Would you like this hotel?\nB: No, the other hotel is better.",funFact:"'Unter anderem' (among other things), abbreviated 'u.a.', is very common in German writing."},
{type:"teach",trg:"alles",src:"everything",pos:"pron",gender:null,note:"Pronoun. The neuter form of 'all'. Alles klar? = All clear?",example:"A: Hast du alles?\nB: Ja, ich habe alles. Wir können gehen.",exampleSrc:"A: Do you have everything?\nB: Yes, I have everything. We can go.",funFact:"'Alles Gute!' (All the best!) is the standard wish for birthdays, farewells, and any occasion."},
{type:"teach",trg:"der Eintritt",src:"the entry, the admission",pos:"noun",gender:"m",note:"Masculine noun. Ein (in) + Tritt (step). Admission fee: der Eintrittspreis.",example:"A: Was kostet der Eintritt?\nB: Der Eintritt kostet zehn Euro.",exampleSrc:"A: How much is the admission?\nB: The admission is ten euros.",funFact:"Many Berlin museums have 'Eintritt frei' (free admission) on the first Sunday of each month."},
{type:"mc",q:"'Der See' is masculine and means 'the lake'. What does 'die See' (feminine) mean?",opts:["the sea","the lake","the river","the pond"],ans:"the sea",hint:"Changing the article from masculine to feminine gives a completely different body of water."},
{type:"fb",s:"Was kostet der {1}?",a:["Eintritt"],opts:["Eintritt","Ausflug","Blick","Prospekt"],hint:"You want to know the price to get into a place.",sSrc:"How much does the admission cost?"},
{type:"mc",q:"What does 'Vorsicht!' mean when you see it on a sign?",opts:["Welcome!","Caution!","Exit!","Open!"],ans:"Caution!",hint:"This word warns you to be careful about something."},
{type:"match",pairs:[{trg:"das Foto",src:"photo"},{trg:"die Karte",src:"map/ticket"},{trg:"das Schild",src:"sign"},{trg:"die Hilfe",src:"help"},{trg:"das Meer",src:"sea"}]},
{type:"mc",q:"Was bedeutet 'das Reisebüro'?",opts:["the information, the information desk","the sign","the travel agency","everything"],ans:"the travel agency",hint:"A compound: 'Reise' (journey) + 'Büro' (office). Where you book trips."},
{type:"fb",s:"Ja, {1} empfiehlt dieses Lokal.",a:["der Reiseführer"],opts:["der Ausflug","die Karte","der Reiseführer","die Vorsicht"],hint:"A person or book that leads travelers. Compound: Reise (travel) + Führer (guide).",sSrc:"Yes, the guide recommends this restaurant."},
{type:"mc",q:"Was bedeutet 'ander'?",opts:["the travel guide (book or person)","the view, the glance","the information, the information desk","other, different"],ans:"other, different",hint:"This adjective marks a distinction from what was just mentioned. Used as 'ein anderer' (one more, one else)."},
{type:"fb",s:"Hast du {1}?",a:["alles"],opts:["alles","die Vorsicht","die Auskunft","das Beispiel"],hint:"The neuter singular form of 'all.' Means 'everything' as a standalone pronoun.",sSrc:"Do you have everything?"}
,{type:"match",pairs:[{trg:"die Polizei",src:"the police"},{trg:"der Laden",src:"the shop (casual)"},{trg:"das Restaurant",src:"the restaurant"},{trg:"müssen",src:"must, to have to"},{trg:"dürfen",src:"may, to be allowed to"},{trg:"möchten",src:"would like"}]},{type:"match",pairs:[{trg:"geben",src:"to give"},{trg:"zeigen",src:"to show, to point"},{trg:"lesen",src:"to read"},{trg:"hören",src:"to hear"},{trg:"kurz",src:"short (length or time)"},{trg:"die Frage",src:"the question"}]},{type:"match",pairs:[{trg:"das Problem",src:"the problem"},{trg:"schnell",src:"fast, quick"},{trg:"anfangen",src:"to start, to begin"},{trg:"bekannt",src:"well-known, famous"},{trg:"klar",src:"clear, obvious"},{trg:"gleich",src:"same, equal; right away"}]},{type:"match",pairs:[{trg:"spielen",src:"to play"},{trg:"sitzen",src:"to sit (state)"},{trg:"fahren",src:"to drive, to go by vehicle"},{trg:"der Spaß",src:"fun"},{trg:"das Stück",src:"piece, item"},{trg:"bekommen",src:"to get, to receive"}]},{type:"match",pairs:[{trg:"der Fluss",src:"the river"},{trg:"schließen",src:"to close"},{trg:"gern(e)",src:"gladly, with pleasure"},{trg:"trinken",src:"to drink"},{trg:"schon",src:"already"},{trg:"vielleicht",src:"perhaps, maybe"}]},{type:"match",pairs:[{trg:"wieder",src:"again"},{trg:"über",src:"over, about, across"},{trg:"breit",src:"wide, broad"},{trg:"der Kiosk",src:"the kiosk"},{trg:"der Laden",src:"the shop, the store"},{trg:"das Dorf",src:"the village"}]},{type:"match",pairs:[{trg:"der Anschluss",src:"the connection (transit)"},{trg:"hoch",src:"high, tall"},{trg:"zurück",src:"back, backwards"},{trg:"besichtigen",src:"to visit, to tour (a place)"},{trg:"halten",src:"to hold, to stop"},{trg:"dauern",src:"to last, to take (time)"}]},{type:"match",pairs:[{trg:"leihen",src:"to lend, to borrow"},{trg:"zeigen",src:"to show"},{trg:"grade",src:"just, right now (colloquial)"},{trg:"der Blick",src:"the view, the glance"},{trg:"der Ausflug",src:"the excursion, the day trip"},{trg:"die Führung",src:"the guided tour"}]},{type:"match",pairs:[{trg:"der Prospekt",src:"the brochure, the flyer"},{trg:"das Reisebüro",src:"the travel agency"},{trg:"brauchen",src:"to need"}]}]}
]};

